-- Schema for Domain: quality | Business: Agriculture | Version: v1_mvm
-- Generated on: 2026-05-01 18:45:53

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`quality` COMMENT 'SSOT for all quality assurance and food safety compliance data across production and supply chain. Manages COA records, HACCP critical control point logs, MRL testing results, GAP/GMP audit findings, GFSI certification status (SQF, BRC, IFS), FSMA compliance records, inspection programs, testing protocols, non-conformance tracking, and corrective actions. Integrates with SAP S/4HANA QM module and supports USDA, FDA, and FSIS regulatory reporting. Maintains certification readiness for GLOBALG.A.P. audits.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`inspection` (
    `inspection_id` BIGINT COMMENT 'Unique system-generated identifier for each inspection event. Primary key for the quality inspection master record.',
    `audit_id` BIGINT COMMENT 'Foreign key linking to quality.quality_audit. Business justification: Inspections are frequently conducted as part of a formal quality audit program (e.g., a GFSI audit includes physical facility inspections, a GLOBALG.A.P. audit includes field inspections). Linking ins',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: GAP and food safety inspections are scoped to specific commodities (e.g., leafy greens vs. tomatoes). Regulatory reporting (FSMA, USDA GAP) and inspection scheduling require commodity-level inspection',
    `conservation_practice_id` BIGINT COMMENT 'Foreign key linking to land.conservation_practice. Business justification: GAP audits evaluate specific BMPs in place at time of inspection (gap_module_soil_amendments_score, gap_module_field_sanitation_score). Auditors must reference which conservation_practice record was a',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Field and facility inspections (GAP audits, food safety, third-party) incur direct costs (inspector fees, travel) allocated to cost centers. Agriculture operations budget and track inspection costs by',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: GAP and food safety inspections in agriculture are frequently conducted at the crew level — inspecting a specific harvest or packing crews GMP/food safety practices. Linking inspection to the crew be',
    `employee_id` BIGINT COMMENT 'Reference to the individual (internal auditor, third-party inspector, or regulatory officer) who conducted the inspection.',
    `facility_id` BIGINT COMMENT 'Reference to the facility, storage location, processing plant, or field site where the inspection was conducted.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: USDA Organic and GlobalG.A.P. certification inspections are scoped to the entire farm operation (farm_unit), not individual fields or facilities. This link enables farm-level inspection history requir',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP field inspections and FSMA Produce Safety Rule inspections are conducted at the field level. Linking inspection to field enables traceability of which fields passed/failed GAP audits — a core requ',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: USDA AMS grade inspections and GAP inspections evaluate compliance against specific grading standards. The inspection stores grade as denormalized text. Linking to grading_standard enables grade certi',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Inspections in food safety contexts are frequently conducted against a specific HACCP plan — verifying CCP monitoring, critical limits, and corrective action procedures. inspection has haccp_ccp_compl',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Storage location inspections (bin audits, warehouse food safety inspections, USDA/FDA facility checks) are a distinct inspection type in agriculture. inspection already has facility_id but storage_loc',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Vendor facility/site inspections (second-party audits) are a core agricultural procurement process for supplier approval and requalification. This is distinct from goods-receipt inspections already co',
    `actual_date` DATE COMMENT 'The calendar date on which the inspection was actually performed. May differ from scheduled_date due to rescheduling or operational delays.',
    `certification_eligible` BOOLEAN COMMENT 'Indicates whether the inspection outcome qualifies the facility or operation for certification or recertification under the applicable standard. Derived from score thresholds and major non-conformance counts.',
    `certification_standard` STRING COMMENT 'The food safety or agricultural certification standard against which this inspection was conducted (e.g., GLOBALG.A.P., SQF Level 2, BRC Global Standard). Drives checklist selection and certification eligibility assessment.. Valid values are `GLOBALG.A.P.|SQF|BRC|IFS|ISO_22000|FSMA|NOP|HACCP|none`',
    `corrective_action_due_date` DATE COMMENT 'Deadline by which all mandated corrective actions from this inspection must be completed and verified. Drives compliance follow-up scheduling and escalation workflows.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether one or more corrective actions have been mandated as a result of this inspection. Triggers downstream corrective action tracking workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the inspection record was first created in the system. Supports audit trail requirements and data lineage tracking.',
    `end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the inspection activity was concluded, enabling duration calculation and scheduling analytics.',
    `gap_module_ag_water_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Agricultural Water section of a GAP compliance assessment. Evaluates water source testing, microbial standards, irrigation method risk, and water quality records per FSMA and USDA GAP requirements.',
    `gap_module_field_sanitation_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Field Sanitation and Hygiene section of a GAP compliance assessment. Evaluates toilet facilities, handwashing stations, field equipment sanitation, and harvest container cleanliness.',
    `gap_module_soil_amendments_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Soil Amendments section of a GAP compliance assessment. Evaluates manure application intervals, compost treatment standards, and biological soil amendment risk management.',
    `gap_module_traceability_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Traceability and Recordkeeping section of a GAP compliance assessment. Evaluates lot identification, harvest records, chain-of-custody documentation, and recall readiness.',
    `gap_module_worker_health_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Worker Health, Hygiene, and Training section of a GAP compliance assessment. Evaluates handwashing facilities, illness policies, training records, and personal hygiene practices per FSMA Produce Safety Rule requirements.',
    `gis_coordinates` STRING COMMENT 'GPS latitude and longitude coordinates of the inspection site in decimal degrees format, enabling geospatial analysis and field mapping via Esri ArcGIS integration.. Valid values are `^-?([1-8]?[0-9](.[0-9]+)?|90(.0+)?),s*-?(1[0-7][0-9](.[0-9]+)?|[1-9]?[0-9](.[0-9]+)?|180(.0+)?)$`',
    `inspection_number` STRING COMMENT 'Externally-known business identifier for the inspection event, used in regulatory submissions, audit trails, and cross-system references (e.g., SAP QM inspection lot number).. Valid values are `^INS-[0-9]{4}-[0-9]{6}$`',
    `inspection_scope` STRING COMMENT 'Operational area or stage of the agricultural supply chain covered by this inspection event (e.g., field operations, post-harvest handling, cold storage, processing facility, inbound receiving). [ENUM-REF-CANDIDATE: field|post_harvest|storage|processing|supply_chain|receiving|pre_operational — 7 candidates stripped; promote to reference product]',
    `inspection_status` STRING COMMENT 'Current lifecycle state of the inspection record, tracking progression from scheduling through completion and review.. Valid values are `scheduled|in_progress|completed|cancelled|pending_review`',
    `inspection_type` STRING COMMENT 'Classification of the inspection by its regulatory or operational framework. Determines the checklist, scoring methodology, and applicable standards applied during the inspection. [ENUM-REF-CANDIDATE: GAP|GMP|HACCP|FSMA|GLOBALG.A.P.|pre_operational|receiving|internal_audit|FSIS|APHIS — promote to reference product]. Valid values are `GAP|GMP|HACCP|FSMA|GLOBALG.A.P.|pre_operational|receiving|internal_audit`',
    `inspector_credential` STRING COMMENT 'Certification or credential held by the inspector (e.g., PCQI - Preventive Controls Qualified Individual, Lead Auditor ISO 22000, GLOBALG.A.P. approved CB auditor). Validates inspector qualification for the inspection type.',
    `inspector_organization` STRING COMMENT 'Name of the organization or agency the inspector represents (e.g., USDA AMS, FDA district office, third-party certification body such as NSF, SGS, or Bureau Veritas). Distinguishes internal from external inspections.',
    `location_description` STRING COMMENT 'Free-text description of the specific location inspected, such as field block identifier, warehouse bay, processing line number, or cold storage unit. Complements the structured facility_id reference.',
    `major_nonconformance_count` STRING COMMENT 'Number of major non-conformances (critical findings) identified during the inspection. Major non-conformances typically result in automatic certification failure or mandatory corrective action before re-inspection.',
    `minor_nonconformance_count` STRING COMMENT 'Number of minor non-conformances identified during the inspection. Minor findings require corrective action within a defined timeframe but do not automatically disqualify certification.',
    `notes` STRING COMMENT 'Free-text field for inspector observations, contextual remarks, environmental conditions at time of inspection, or other qualitative information not captured in structured fields.',
    `observation_count` STRING COMMENT 'Number of observations or recommendations noted during the inspection that do not constitute formal non-conformances but indicate areas for improvement.',
    `outcome` STRING COMMENT 'Overall pass/fail determination for the inspection event. Conditional pass indicates the operation may continue subject to corrective actions within a defined timeframe.. Valid values are `pass|fail|conditional_pass|pending`',
    `overall_score` DECIMAL(18,2) COMMENT 'Numeric score or percentage representing the aggregate compliance performance across all inspection criteria evaluated. Scoring methodology varies by inspection type (e.g., GLOBALG.A.P. percentage, SQF numeric grade).',
    `reinspection_date` DATE COMMENT 'Scheduled date for the follow-up re-inspection when reinspection_required is true. Used for compliance calendar management and audit scheduling.',
    `reinspection_required` BOOLEAN COMMENT 'Indicates whether a follow-up re-inspection is required to verify corrective action completion or to re-evaluate a failed inspection outcome.',
    `report_issued_date` DATE COMMENT 'Date on which the formal inspection report was issued to the inspected party. Starts the clock for corrective action response deadlines and certification validity periods.',
    `report_number` STRING COMMENT 'Official report number assigned by the regulatory body or certification organization to the formal inspection report document. Used for regulatory submission tracking and document management.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which the inspection was originally scheduled to occur, used for compliance planning and audit scheduling.',
    `standard_version` STRING COMMENT 'The specific version or edition of the certification standard applied during the inspection (e.g., GLOBALG.A.P. v5.4, SQF Edition 9). Critical for audit traceability as standards evolve.',
    `start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the inspection activity commenced on-site or in the facility, used for duration tracking and regulatory audit trails.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the inspection record was most recently modified. Supports change tracking, data lineage, and audit trail requirements.',
    CONSTRAINT pk_inspection PRIMARY KEY(`inspection_id`)
) COMMENT 'Master record for all quality inspections across field, post-harvest, storage, processing, and supply chain operations. Captures inspection type (GAP, GMP, HACCP verification, FSMA, GLOBALG.A.P., pre-operational, receiving, GAP compliance assessment), scope, facility or field location, scheduled and actual dates, inspector identity, overall pass/fail outcome, and score or grade. For GAP compliance assessments: standard version, module-level scoring (worker health, agricultural water, soil amendments, field sanitation, traceability), and certification eligibility. Regulatory body association (USDA, FDA, FSIS, APHIS). SSOT for all inspection events in the quality domain.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`inspection_finding` (
    `inspection_finding_id` BIGINT COMMENT 'Unique surrogate identifier for each individual inspection or audit finding record. Primary key for the inspection_finding data product in the quality domain SSOT.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: MRL exceedance findings (mrl_exceedance_flag=true) must trace back to the specific EPA-registered agrochemical product. Regulatory reportable findings and corrective action prioritization require know',
    `audit_id` BIGINT COMMENT 'Foreign key linking to quality.quality_audit. Business justification: Inspection findings can be discovered during formal quality audits (GFSI, GAP, etc.). The inspection_finding table has audit_type and standard_scheme fields that duplicate quality_audit master data. T',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Inspection findings (MRL exceedances, GAP violations, food safety risks) are commodity-specific. Regulatory agencies (FDA, USDA) require findings to be reported by commodity. A compliance officer trac',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific commodity lot or product batch associated with this finding, if applicable. Enables traceability from finding to affected product for recall management, COA linkage, and MRL compliance tracking.',
    `conservation_practice_id` BIGINT COMMENT 'Foreign key linking to land.conservation_practice. Business justification: GAP and NRCS audit findings cite specific conservation practices that are non-compliant or absent (e.g., buffer strip not maintained, cover crop not established). inspection_finding has gap_gmp_catego',
    `facility_id` BIGINT COMMENT 'Reference to the facility, farm site, processing plant, or storage location where this finding was identified. Supports facility-level compliance reporting and FSMA Preventive Controls facility registration linkage.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP inspection findings (field sanitation, agricultural water, soil amendments) are scored per field. Linking inspection_finding to field enables field-level risk scoring and finding trend analysis — ',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Inspection findings are discovered during quality inspections. The inspection_finding table has inspection_area and audit_type fields suggesting findings can come from inspections. This FK links findi',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: When mrl_exceedance_flag is set on an inspection finding, the specific regulatory tolerance that was exceeded must be referenced for regulatory_reportable_flag determination, agency notification, and ',
    `employee_id` BIGINT COMMENT 'Reference to the party (internal auditor, second-party customer auditor, or third-party certification body inspector) who identified and recorded this finding. Supports auditor qualification tracking and finding pattern analysis.',
    `prior_finding_inspection_finding_id` BIGINT COMMENT 'Reference to the earlier finding record that this finding is a recurrence of. Populated when repeat_finding_flag is True. Enables trend analysis and systemic non-conformance identification across audit cycles.',
    `safety_event_id` BIGINT COMMENT 'Foreign key linking to workforce.safety_event. Business justification: Inspection findings related to WPS violations, pesticide handler exposure, or worker safety GMP failures directly correspond to safety incidents. Agriculture regulators (EPA WPS, OSHA) require cross-r',
    `ccp_reference` STRING COMMENT 'Identifier of the HACCP Critical Control Point (CCP) associated with this finding, if applicable (e.g., CCP-01 Thermal Processing, CCP-02 Metal Detection). Links the finding to the HACCP plan for hazard analysis and corrective action tracking.',
    `certification_impact` STRING COMMENT 'Assessed impact of this finding on the facilitys or operations current certification status under the applicable GFSI scheme or GLOBALG.A.P. certification. Populated by the lead auditor or certification body. Drives certification status update workflows.. Valid values are `none|grade_reduction|conditional_pass|suspension|withdrawal`',
    `closure_due_date` DATE COMMENT 'Deadline by which the corrective action must be fully implemented and the finding verified as closed. Distinct from response_due_date (plan submission) — this is the implementation completion deadline. Used for certification readiness tracking.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp when this finding record was first captured in the system. Used for data lineage, SLA tracking, and regulatory audit trails. Populated automatically on insert.',
    `detected_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when this finding was identified or observed during the inspection or audit. Distinct from record creation audit timestamp. Critical for PHI (Pre-Harvest Interval) and REI (Restricted Entry Interval) compliance timelines.',
    `disposition` STRING COMMENT 'The disposition decision for any product or material implicated by this finding. Applicable when the finding is associated with a specific commodity lot. Aligns with SAP QM usage decision codes and FSMA preventive controls disposition requirements.. Valid values are `accept|rework|reject|hold|destroy|release_with_deviation`',
    `evidence_document_reference` STRING COMMENT 'Reference identifier or URL to supporting evidence documents (photographs, laboratory test results, COA, temperature logs, pesticide application records) stored in the document management system. Supports audit trail completeness and regulatory submission packages.',
    `finding_classification` STRING COMMENT 'Severity classification of the finding per food safety and quality management standards. Critical = immediate food safety risk or regulatory violation; Major = significant non-conformance likely to result in product failure; Minor = partial non-conformance; Observation = noted deviation not yet non-conforming; Opportunity for Improvement (OFI) = best-practice recommendation. Drives corrective action urgency and certification impact.. Valid values are `critical|major|minor|observation|opportunity_for_improvement`',
    `finding_description` STRING COMMENT 'Detailed narrative description of the non-conformance, observation, or opportunity for improvement. Documents what was found, where, and under what conditions. Supports root cause analysis and corrective action planning.',
    `finding_number` STRING COMMENT 'Externally-known, human-readable business identifier for this finding (e.g., QF-2024-000123). Used in corrective action requests, audit reports, and regulatory submissions. Sourced from SAP QM notification numbering.. Valid values are `^QF-[0-9]{4}-[0-9]{6}$`',
    `finding_status` STRING COMMENT 'Current lifecycle state of the finding from identification through closure. Drives corrective action workflows and certification readiness dashboards. [ENUM-REF-CANDIDATE: open|under_review|corrective_action_pending|corrective_action_submitted|verified_closed|accepted|waived — promote to reference product]',
    `finding_title` STRING COMMENT 'Short, human-readable title summarizing the nature of the non-conformance or observation (e.g., Inadequate pest control records, CCP temperature log gap). Used in dashboards, corrective action requests, and management reports.',
    `food_safety_risk_flag` BOOLEAN COMMENT 'Indicates whether this finding poses a direct food safety risk requiring immediate escalation under HACCP or FSMA protocols. When True, triggers mandatory notification workflows to the food safety team and may require product hold or recall assessment.',
    `gap_gmp_category` STRING COMMENT 'Categorizes the finding within the GAP/GMP compliance framework. Supports structured reporting to USDA, FDA, and GLOBALG.A.P. certification bodies and enables category-level trend analysis for continuous improvement programs. [ENUM-REF-CANDIDATE: GAP|GMP|HACCP|sanitation|traceability|pest_control|water_quality|worker_health|equipment|documentation — promote to reference product]',
    `inspection_area` STRING COMMENT 'The physical area, zone, process step, or operational unit where the finding was identified (e.g., receiving dock, cold storage, processing line 3, field block A, irrigation system). Supports spatial analysis of non-conformance patterns.',
    `inspector_notes` STRING COMMENT 'Free-text field for additional contextual notes, observations, or recommendations recorded by the inspector or auditor at the time of the finding. Supplements the structured finding_description with qualitative context for root cause analysis.',
    `ipm_related_flag` BOOLEAN COMMENT 'Indicates whether this finding is related to Integrated Pest Management (IPM) program compliance, including pest scouting records, pesticide application logs, PHI (Pre-Harvest Interval) adherence, or REI (Restricted Entry Interval) compliance.',
    `mrl_exceedance_flag` BOOLEAN COMMENT 'Indicates whether this finding involves a pesticide or chemical residue exceeding the Maximum Residue Limit (MRL) as defined by EPA, Codex Alimentarius, or importing country regulations. Triggers mandatory product hold and regulatory notification.',
    `objective_evidence` STRING COMMENT 'Factual, verifiable evidence supporting the finding — records reviewed, measurements taken, observations made, or interviews conducted. Required by ISO 19011 and all GFSI scheme auditing protocols to substantiate the finding classification.',
    `parent_event_type` STRING COMMENT 'Discriminator indicating whether the parent event was a quality inspection (routine operational check) or a formal audit (internal, second-party, or third-party certification audit). Drives workflow routing and reporting.. Valid values are `inspection|audit`',
    `regulatory_agency` STRING COMMENT 'The regulatory authority to which this finding must be reported, if regulatory_reportable_flag is True. Determines the specific reporting format, timeline, and submission channel required. [ENUM-REF-CANDIDATE: USDA|FDA|FSIS|EPA|APHIS|OSHA|state_agency|none — 8 candidates stripped; promote to reference product]',
    `regulatory_reportable_flag` BOOLEAN COMMENT 'Indicates whether this finding must be reported to a regulatory authority (USDA, FDA, FSIS, EPA, APHIS). When True, triggers mandatory regulatory notification workflows and documentation requirements under FSMA, FSIS directives, or EPA regulations.',
    `repeat_finding_flag` BOOLEAN COMMENT 'Indicates whether this finding is a recurrence of a previously identified non-conformance at the same location or process. Repeat findings trigger escalated corrective action requirements under GFSI schemes and may impact certification grade.',
    `response_due_date` DATE COMMENT 'Required deadline by which a corrective action plan or response must be submitted for this finding. Determined by finding classification and standard scheme requirements (e.g., critical findings typically require 24-hour response; major findings 30 days). Drives SLA monitoring.',
    `risk_severity_rating` STRING COMMENT 'Risk-based severity assessment of the findings potential impact on food safety, product quality, regulatory compliance, or business continuity. Distinct from finding_classification (which is scheme-defined); this is the internal risk management rating used for prioritization and HACCP hazard analysis alignment.. Valid values are `critical|high|medium|low`',
    `sap_qm_notification_number` STRING COMMENT 'The SAP S/4HANA QM module notification number corresponding to this finding. Enables bidirectional traceability between the lakehouse silver layer record and the operational system of record for corrective action management and ERP integration.',
    `standard_clause_reference` STRING COMMENT 'The specific clause, control point, element, or requirement number within the applicable standard scheme against which this finding was raised (e.g., FSMA 21 CFR Part 117.135, GLOBALG.A.P. CB.7.1, SQF Element 2.4.3, BRC Clause 4.11.2, IFS Requirement 4.18.1). Essential for certification body reporting and corrective action traceability.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp when this finding record was last modified. Tracks changes to status, corrective action assignments, or evidence updates for compliance audit trail purposes.',
    `verified_closed_date` DATE COMMENT 'Actual date on which the finding was verified as effectively closed following corrective action implementation. Populated by the verifying auditor or quality manager. Used to calculate closure cycle time and assess corrective action effectiveness.',
    CONSTRAINT pk_inspection_finding PRIMARY KEY(`inspection_finding_id`)
) COMMENT 'Individual findings, observations, and deficiencies identified during quality inspections or formal audits (internal, second-party, third-party certification). Records parent event reference and type (inspection or audit), finding classification (critical, major, minor, observation, opportunity for improvement), applicable standard clause reference (FSMA 21 CFR Part 117, GLOBALG.A.P. control point, SQF Element, BRC Clause, IFS requirement), description of non-conformance or observation, objective evidence, risk severity rating, required response timeline, and disposition. Unified SSOT for ALL quality findings regardless of detection context — replaces separate audit finding tracking. Drives corrective action generation and certification status updates.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`corrective_action` (
    `corrective_action_id` BIGINT COMMENT 'Unique system-generated identifier for the Corrective and Preventive Action (CAPA) record. Primary key for the corrective_action data product in the quality domain.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: CAPAs triggered by agrochemical misuse (wrong product applied, PHI violation, restricted-use violation) must reference the specific agrochemical product. An agrochemist or compliance officer managing ',
    `audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: corrective_action has source_type (STRING) and source_reference_id (BIGINT) as a polymorphic reference. When source_type = audit, adding a typed audit_id FK provides a direct reference to the audit ',
    `case_id` BIGINT COMMENT 'Foreign key linking to customer.case. Business justification: Customer complaint-driven CAPA management: when a customer case (e.g., MRL exceedance complaint, contamination report) triggers a corrective action, the CAPA must reference the originating customer ca',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: CAPAs in agriculture are commodity-specific — an MRL exceedance CAPA for strawberries differs from one for spinach. Commodity-level CAPA trend analysis is required for GFSI scheme compliance and buyer',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: CAPAs in agriculture are frequently triggered by commodity lot failures (MRL exceedance, mycotoxin, grade rejection). Linking CAPA to the affected lot enables effectiveness tracking, lot disposition f',
    `conservation_practice_id` BIGINT COMMENT 'Foreign key linking to land.conservation_practice. Business justification: NRCS EQIP and GAP audit corrective actions frequently mandate installation or modification of specific conservation practices (buffer strips, cover crops). Linking CAPA to conservation_practice enable',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: CAPA execution in agriculture incurs labor, materials, and process-change costs charged to cost centers. Cost-of-quality management accounting and CAPA ROI analysis require tracking CAPA expenditures ',
    `facility_id` BIGINT COMMENT 'Identifier of the facility, processing plant, farm site, or warehouse where the nonconformance or finding originated and where the corrective action is to be implemented. Links to the facility master record.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP and FSMA corrective actions are frequently field-specific (e.g., cease irrigation from contaminated source on field X, implement buffer zone on field Y). Linking corrective_action to field enables',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: CAPA remediation expenditures (equipment cleaning, retesting, process upgrades) are posted to GL accounts. Financial period-close and cost-of-quality P&L reporting in agriculture require CAPA costs ma',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Corrective actions in food safety are frequently generated in response to HACCP CCP deviations. The corrective_action table currently has a denormalized haccp_ccp_reference STRING field that stores a ',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: Corrective actions (CAPAs) are generated in response to inspection findings. The corrective_action table has source_type and source_reference_number (string-based) but lacks structured FK to findings.',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: corrective_action has source_type (STRING) and source_reference_id (BIGINT) as a polymorphic reference. When source_type = inspection, adding a typed inspection_id FK provides a direct reference to ',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: CAPAs triggered by MRL exceedances must reference the specific regulatory tolerance to document the preventive action scope, verify effectiveness against the threshold, and satisfy FSMA Preventive Con',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Corrective actions are initiated in response to nonconformances. The corrective_action table has source_type and source_reference_number (string-based) but lacks structured FK to nonconformance. This ',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: CAPAs triggered by organic certification violations (prohibited substance use, audit nonconformances) must reference the specific organic certification at risk. An organic program manager tracking CAP',
    `parent_capa_corrective_action_id` BIGINT COMMENT 'Reference to a parent CAPA record when this CAPA was generated as a follow-up due to ineffective closure of a prior action. Enables CAPA lineage tracking and recurrence chain analysis.',
    `employee_id` BIGINT COMMENT 'Identifier of the employee or team lead assigned as the primary owner accountable for implementing the corrective and preventive action. Links to the workforce/employee master record in SAP SuccessFactors.',
    `workforce_certification_id` BIGINT COMMENT 'Foreign key linking to workforce.workforce_certification. Business justification: Agriculture CAPAs triggered by pesticide misuse or food safety violations frequently mandate that responsible employees obtain or renew a specific certification (pesticide applicator license, HACCP ce',
    `safety_event_id` BIGINT COMMENT 'Foreign key linking to workforce.safety_event. Business justification: In agriculture, CAPAs are frequently triggered directly by safety events (pesticide exposure, WPS violations). OSHA and FSMA require traceable linkage from the originating safety incident to the corre',
    `training_event_id` BIGINT COMMENT 'Foreign key linking to workforce.training_event. Business justification: Under FSMA preventive controls and GFSI schemes, corrective actions frequently mandate a specific training event as the preventive measure. Linking CAPA records to the fulfilling training event is req',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: CAPAs triggered by vendor non-performance must reference the specific vendor contract to enforce penalty clauses and contractual corrective action requirements. corrective_action has vendor_id but not',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Supplier Corrective Action Requests (SCARs) are a named agriculture procurement process where CAPAs are formally issued to vendors. Quality teams must link a CAPA to the responsible vendor for SCAR tr',
    `actual_closure_date` DATE COMMENT 'Actual date on which all corrective and preventive actions were fully implemented and the CAPA record was formally closed following successful verification. Compared against target_completion_date to measure on-time closure performance.',
    `capa_number` STRING COMMENT 'Externally-known business identifier for the CAPA record, formatted as CAPA-{YEAR}-{SEQUENCE}. Used for cross-referencing in audit reports, regulatory submissions, and SAP QM notification workflows.. Valid values are `^CAPA-[0-9]{4}-[0-9]{6}$`',
    `capa_status` STRING COMMENT 'Current lifecycle status of the CAPA record, tracking progression from initial opening through root cause analysis, implementation, verification, and closure. Drives workflow routing in SAP S/4HANA QM.. Valid values are `open|in_progress|pending_verification|closed|overdue|cancelled`',
    `capa_type` STRING COMMENT 'Classifies whether the action is purely corrective (addressing an existing nonconformance), purely preventive (addressing a potential risk), or both. Determines reporting category for FSMA, SQF, BRC, and IFS compliance.. Valid values are `corrective|preventive|both`',
    `certification_standard` STRING COMMENT 'The food safety or agricultural certification standard under which this CAPA was generated or is required to be documented. Determines the specific documentation and closure requirements applicable to the CAPA. [ENUM-REF-CANDIDATE: SQF|BRC|IFS|GLOBALG.A.P.|FSMA|HACCP|ISO_22000|USDA_NOP|other — promote to reference product]. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSMA|HACCP|ISO_22000|USDA_NOP|other`',
    `corrective_action_description` STRING COMMENT 'Detailed description of the specific corrective action(s) taken to eliminate the identified root cause and prevent recurrence of the nonconformance. Documents what was done, how it was done, and the expected outcome.',
    `created_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the CAPA record was first created in the data platform. Used for data lineage, audit trail, and silver layer ingestion tracking.',
    `department` STRING COMMENT 'Name of the department or operational area responsible for implementing the corrective and preventive action (e.g., Quality Assurance, Production, Procurement, Logistics). Used for workload assignment and KPI reporting.',
    `effectiveness_review_date` DATE COMMENT 'Date on which the effectiveness review was conducted to assess whether the implemented corrective and preventive actions successfully eliminated the root cause and prevented recurrence of the nonconformance.',
    `effectiveness_review_notes` STRING COMMENT 'Narrative notes from the effectiveness review, documenting evidence reviewed, observations made, and rationale for the effectiveness determination. Supports audit trail and continuous improvement documentation.',
    `effectiveness_review_outcome` STRING COMMENT 'Outcome of the post-implementation effectiveness review, assessing whether the corrective and preventive actions successfully eliminated the root cause and prevented recurrence. A not_effective outcome triggers a new CAPA cycle.. Valid values are `effective|partially_effective|not_effective|pending_review`',
    `finding_description` STRING COMMENT 'Detailed narrative description of the nonconformance, inspection finding, audit observation, or food safety incident that triggered this CAPA. Provides the factual basis for root cause analysis and corrective action planning.',
    `fsma_reportable_flag` BOOLEAN COMMENT 'Indicates whether this CAPA is associated with a food safety event that requires reporting or documentation under the Food Safety Modernization Act (FSMA), including Preventive Controls, Produce Safety, or Foreign Supplier Verification Program requirements.',
    `gap_gmp_violation_flag` BOOLEAN COMMENT 'Indicates whether the nonconformance or finding that triggered this CAPA constitutes a violation of Good Agricultural Practices (GAP) or Good Manufacturing Practices (GMP). Flags records requiring mandatory regulatory reporting.',
    `immediate_containment_action` STRING COMMENT 'Description of the immediate containment or disposition action taken at the time of the finding to prevent affected product from reaching the market or causing further harm (e.g., product quarantine, lot hold, process stoppage). Distinct from the root-cause-based corrective action.',
    `opened_timestamp` TIMESTAMP COMMENT 'Date and time when the CAPA record was formally opened and entered into the quality management system. Represents the principal business event timestamp for the CAPA lifecycle. Used for aging analysis and regulatory timeliness reporting.',
    `preventive_action_description` STRING COMMENT 'Detailed description of the systemic preventive action(s) implemented to eliminate the potential cause of a nonconformance or to prevent recurrence across similar processes, products, or facilities. Addresses systemic risk beyond the immediate corrective fix.',
    `priority` STRING COMMENT 'Business priority level assigned to the CAPA based on the severity of the finding, food safety risk, regulatory impact, and potential for recurrence. Drives escalation thresholds and target completion timelines.. Valid values are `critical|high|medium|low`',
    `recurrence_flag` BOOLEAN COMMENT 'Indicates whether this CAPA addresses a recurring nonconformance or finding that has been previously documented. Recurring issues trigger escalated review and systemic corrective action requirements under GFSI standards.',
    `regulatory_requirement` STRING COMMENT 'Specific regulatory clause, standard requirement, or certification criterion that the CAPA addresses (e.g., FSMA 21 CFR Part 117.150, GLOBALG.A.P. IFA v6 AF 4.1, SQF Element 2.5.3). Supports regulatory reporting and audit readiness.',
    `responsible_party_name` STRING COMMENT 'Full name of the employee or team lead assigned as the primary owner of the CAPA. Stored for audit trail and regulatory reporting purposes where the named individual must be identified in compliance documentation.',
    `root_cause_category` STRING COMMENT 'High-level classification of the root cause to enable trend analysis and systemic issue identification across the quality management system. Categories align with standard fishbone/Ishikawa diagram branches used in agricultural food safety programs.. Valid values are `people|process|equipment|material|environment|management_system`',
    `root_cause_description` STRING COMMENT 'Detailed narrative of the identified root cause(s) of the nonconformance or finding, as determined through the selected root cause analysis method. Forms the foundation for corrective and preventive action planning.',
    `root_cause_method` STRING COMMENT 'Structured methodology used to identify the root cause of the nonconformance or finding. Common methods include 5-Why analysis, fishbone (Ishikawa) diagram, fault tree analysis, Failure Mode and Effects Analysis (FMEA), Pareto analysis, or brainstorming. [ENUM-REF-CANDIDATE: 5_why|fishbone|fault_tree|failure_mode_effects_analysis|pareto|brainstorming|other — promote to reference product]',
    `sap_qm_notification_number` STRING COMMENT 'SAP S/4HANA QM module notification number associated with this CAPA record. Enables bidirectional traceability between the lakehouse silver layer and the operational SAP QM workflow system.',
    `source_reference_number` STRING COMMENT 'Human-readable business identifier of the originating record (e.g., nonconformance report number, audit finding reference, inspection report number). Supports cross-document traceability in regulatory submissions and audit packages.',
    `source_type` STRING COMMENT 'Categorizes the originating trigger for the CAPA record. Indicates whether the action was initiated from an inspection finding, nonconformance report, audit finding, environmental monitoring positive, customer complaint, Maximum Residue Limit (MRL) exceedance, food safety incident, or internal observation. [ENUM-REF-CANDIDATE: inspection_finding|nonconformance|audit_finding|environmental_monitoring|customer_complaint|mrl_exceedance|food_safety_incident|internal_observation — promote to reference product]',
    `target_completion_date` DATE COMMENT 'Planned date by which all corrective and preventive actions must be fully implemented and ready for verification. Used for overdue tracking, escalation management, and regulatory audit readiness reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the CAPA record was last modified in the data platform. Supports change tracking, audit trail requirements, and incremental data pipeline processing.',
    `verification_date` DATE COMMENT 'Date on which the verification activity was performed to confirm that the corrective and preventive actions were implemented as planned and are effective.',
    `verification_method` STRING COMMENT 'Description of the method used to verify that the corrective and preventive actions were effectively implemented (e.g., re-inspection, laboratory testing, process audit, document review, observation). Required for FSMA, SQF, BRC, and IFS closure documentation.',
    CONSTRAINT pk_corrective_action PRIMARY KEY(`corrective_action_id`)
) COMMENT 'CAPA (Corrective and Preventive Action) records generated in response to inspection findings, nonconformances (including MRL exceedances and food safety incidents), audit findings, or environmental monitoring positives. Tracks root cause analysis method (5-Why, fishbone, fault tree), corrective action description, preventive action description, responsible party, target completion date, actual closure date, verification method and date, effectiveness review outcome and review date. Supports FSMA, SQF, BRC, and IFS CAPA requirements. Integrates with SAP S/4HANA QM notification workflows. Links to originating finding or nonconformance for full traceability.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`nonconformance` (
    `nonconformance_id` BIGINT COMMENT 'Unique system-generated identifier for each nonconformance record. Primary key for the nonconformance master record in the quality management system.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Nonconformances for MRL exceedances currently store pesticide_active_ingredient as denormalized text. Linking to agrochemical_product enables traceability to the EPA-registered product, supports recal',
    `audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: When a nonconformance is detected during a formal audit (detection_source = audit), adding audit_id FK provides a direct typed reference to the audit record. nonconformance has gap_audit_finding_ref',
    `case_id` BIGINT COMMENT 'Foreign key linking to customer.case. Business justification: Customer-facing nonconformance resolution: when a nonconformance (pesticide residue, contamination) affects a customer shipment, a customer case is opened. Linking nonconformance to the customer case ',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Nonconformances are commodity-specific events (MRL exceedance, grade failure, recall). The existing commodity_code is a denormalized plain attribute; replacing it with a proper FK to product.commodity',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Nonconformance events in agriculture (MRL exceedance, grade failure, food safety incident) are tied to specific commodity lots for recall scope determination, regulatory notification, and disposition.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Nonconformances against contracted commodity specifications (moisture, grade, MRL) must reference the contract to assess penalty clauses, volume shortfall impacts, and contract compliance reporting. T',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Nonconformance disposal, rework, and retesting costs are charged to cost centers in agricultural operations. Cost-of-quality reporting by farm unit or facility requires this link for management accoun',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: When a nonconformance (MRL exceedance, food safety incident) affects product allocated to a specific buyer, customer notification is a regulatory and commercial obligation under FSMA and trade contrac',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: Nonconformance detected at customer receiving location: in agriculture, product failures (contamination, MRL exceedance) are often detected at the customers facility. Linking nonconformance to delive',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: MRL exceedances, contaminated water sources, and soil amendment violations in agriculture are traced to specific fields. Linking nonconformance to field enables field-level root cause analysis and sup',
    `field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.equipment_field_operation. Business justification: Field operations with PHI/REI violations, off-target spray events, or application rate exceedances directly generate nonconformances. Linking nonconformance to the originating equipment_field_operatio',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Nonconformances trigger financial postings — disposal costs, rework, customer claims, recall expenses — to specific GL accounts. Agriculture operations post NC financial impacts (MRL exceedances, food',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Nonconformances are frequently triggered by grading standard violations (grade-out events, defect threshold exceedances). Linking to the specific grading standard enables buyer dispute resolution, dis',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: Nonconformances are often triggered by specific inspection findings. The nonconformance table has detection_source (string) but lacks a structured FK to the finding that triggered it. This FK enables ',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Nonconformance events are frequently triggered by lab sample results (e.g., MRL exceedance detected in a pesticide residue test, mycotoxin level above threshold). The nonconformance record should refe',
    `master_id` BIGINT COMMENT 'Foreign key linking to product.master. Business justification: Nonconformances reference a specific product SKU (existing plain attribute). Replacing the denormalized sku with a FK to product.master enables product-level quality reporting, buyer dispute resolutio',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the commodity, product, or input material involved in the nonconformance.',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Nonconformance stores applicable_mrl_standard and mrl_threshold_mg_kg as denormalized text/numeric. Linking to mrl_threshold normalizes the regulatory tolerance reference, enabling FSMA reportability ',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Nonconformances involving prohibited substance detection or organic documentation failures directly threaten organic certification status. An organic compliance manager tracking NCs that put organic c',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Nonconformances on incoming goods are detected at goods receipt. Linking NC to the specific GRN enables three-way match dispute resolution, return claim processing, and lot traceability back to the de',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: FSMA and GFSI require traceable employee identification for nonconformance reporting. The existing reported_by plain-text field is a denormalized employee reference; a proper FK supports regulatory ',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: Customer-initiated nonconformances (rejected shipments, spec failures) must trace back to the originating sales order for claims processing, credit memo issuance, and order fulfillment reporting. Agri',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Nonconformances against vendor-supplied agricultural inputs must be traceable to the specific vendor contract to enforce quality penalty clauses and update contract performance records. nonconformance',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: When received agricultural inputs (seeds, chemicals, commodities) fail quality inspection, the supplying vendor must be identified for SCAR issuance, vendor scorecard deduction, return claim initiatio',
    `affected_export_market` STRING COMMENT 'ISO 3-letter country code(s) of export markets impacted by the MRL exceedance or food safety incident. Drives market withdrawal decisions and trade compliance actions.',
    `affected_quantity` DECIMAL(18,2) COMMENT 'Total quantity of product, commodity, or material affected by the nonconformance, expressed in the unit of measure specified in quantity_uom.',
    `affected_value_usd` DECIMAL(18,2) COMMENT 'Estimated financial value of the affected product or commodity in US dollars. Used for financial impact assessment, insurance claims, and EBITDA impact reporting.',
    `corrective_action_closed_date` DATE COMMENT 'Actual date on which the corrective action was verified as complete and effective. Marks closure of the CAPA cycle for this nonconformance.',
    `corrective_action_description` STRING COMMENT 'Description of the corrective and preventive action (CAPA) implemented or planned to address the root cause and prevent recurrence of the nonconformance.',
    `corrective_action_due_date` DATE COMMENT 'Target completion date for the corrective action. Used for CAPA tracking, audit follow-up scheduling, and regulatory compliance deadline management.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the nonconformance record was first created in the quality management system. Supports audit trail, regulatory reporting timelines, and data lineage.',
    `detected_residue_level` DECIMAL(18,2) COMMENT 'Measured pesticide residue concentration in mg/kg (ppm) as determined by laboratory analysis. Populated for nonconformance_type = mrl_exceedance. Compared against applicable MRL standard.',
    `detection_date` DATE COMMENT 'Calendar date on which the nonconformance was first identified or detected. Used for regulatory reporting timelines and corrective action due date calculations.',
    `detection_source` STRING COMMENT 'Origin or mechanism by which the nonconformance was identified. Distinguishes proactive internal detection from reactive external discovery. [ENUM-REF-CANDIDATE: internal_audit|external_audit|laboratory_test|operator_observation|customer_complaint|regulatory_inspection|supplier_notification|automated_sensor — promote to reference product]',
    `disposition_date` DATE COMMENT 'Date on which the disposition decision was formally approved and recorded. Required for regulatory audit trails and FSMA compliance documentation.',
    `disposition_decision` STRING COMMENT 'Final quality disposition decision for the nonconforming product or material. Determines the fate of affected inventory and drives downstream supply chain and financial actions.. Valid values are `release|rework|regrade|destroy|return_to_supplier|hold_pending`',
    `food_safety_incident_subtype` STRING COMMENT 'Specific category of food safety incident. Populated only when nonconformance_type = food_safety_incident. Drives HACCP critical control point review and regulatory reporting requirements.. Valid values are `contamination|foreign_material|allergen|pathogen|chemical`',
    `gap_audit_finding_ref` STRING COMMENT 'Reference number linking this nonconformance to a specific GAP or GMP audit finding. Enables traceability between audit programs and resulting nonconformance records.',
    `gfsi_scheme` STRING COMMENT 'GFSI-benchmarked certification scheme under which this nonconformance was identified or is being managed. Determines applicable audit standard requirements for CAPA and closure.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSSC22000|not_applicable`',
    `hazard_classification` STRING COMMENT 'HACCP hazard classification for food safety incidents. Categorizes the nature of the food safety hazard to guide risk assessment and control measure selection.. Valid values are `biological|chemical|physical|radiological`',
    `incident_closure_status` STRING COMMENT 'Detailed closure workflow status for food safety incidents and major nonconformances. Tracks progression from initial detection through CAPA verification and regulatory sign-off.. Valid values are `open|capa_in_progress|capa_verified|closed|regulatory_pending`',
    `mock_recall_flag` BOOLEAN COMMENT 'Indicates whether this record represents a mock/simulated recall exercise rather than an actual recall event. Required for GFSI, SQF, BRC, and GLOBALG.A.P. certification audit readiness.',
    `nc_status` STRING COMMENT 'Current lifecycle status of the nonconformance record within the quality management workflow.. Valid values are `open|under_investigation|pending_disposition|closed|escalated`',
    `nonconformance_type` STRING COMMENT 'Classification of the nonconformance category. product = physical product defect; process = deviation from SOP/GMP; system = management system gap; mrl_exceedance = Maximum Residue Limit (MRL) exceedance; food_safety_incident = HACCP/FSMA food safety event.. Valid values are `product|process|system|mrl_exceedance|food_safety_incident`',
    `qm_notification_number` STRING COMMENT 'External quality notification number from SAP S/4HANA QM module (Q-notification). Serves as the cross-system business identifier for this nonconformance record.',
    `quantity_uom` STRING COMMENT 'Unit of measure for the affected quantity. Supports MT (Metric Ton), BU (Bushel), CWT (Hundredweight), KG, LB, L, GAL, UNIT, CASE per agricultural industry standards. [ENUM-REF-CANDIDATE: MT|BU|CWT|KG|LB|L|GAL|UNIT|CASE — 9 candidates stripped; promote to reference product]',
    `recall_class` STRING COMMENT 'FDA/USDA recall classification. Class I = serious adverse health consequences or death; Class II = temporary adverse health consequences; Class III = unlikely to cause adverse health consequences. Populated for food safety incidents requiring recall.. Valid values are `I|II|III|not_applicable`',
    `regulatory_agencies_notified` STRING COMMENT 'Comma-separated list of regulatory agencies formally notified of this nonconformance (e.g., FDA, USDA, FSIS, EPA, APHIS). Populated when regulatory_notification_required is True.',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether this nonconformance triggers a mandatory regulatory notification obligation to USDA, FDA, FSIS, EPA, or APHIS. Drives compliance workflow escalation.',
    `root_cause_category` STRING COMMENT 'High-level categorization of the identified root cause of the nonconformance. Supports trend analysis, corrective action prioritization, and CAPA program management. [ENUM-REF-CANDIDATE: raw_material|process_deviation|equipment_failure|human_error|supplier_issue|environmental|pest_contamination|storage_condition — promote to reference product]',
    `root_cause_description` STRING COMMENT 'Detailed narrative description of the identified root cause following investigation. Supports 5-Why or fishbone analysis documentation for CAPA and audit evidence.',
    `severity_level` STRING COMMENT 'Risk-based severity classification of the nonconformance. minor = low risk, no regulatory impact; major = significant deviation requiring corrective action; critical = immediate risk to product integrity or compliance; food_safety_crisis = imminent public health risk requiring recall or regulatory notification.. Valid values are `minor|major|critical|food_safety_crisis`',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent update to the nonconformance record. Supports change tracking, audit trail integrity, and data lineage in the Databricks Silver layer.',
    CONSTRAINT pk_nonconformance PRIMARY KEY(`nonconformance_id`)
) COMMENT 'Unified master record for all quality failures, deviations, and food safety incidents across crop production, livestock operations, processing, and supply chain. Captures nonconformance type (product, process, system, MRL_exceedance, food_safety_incident), severity level (minor, major, critical, food_safety_crisis), affected lot, commodity or product SKU, detection point and source. For standard nonconformances: disposition decision, financial impact estimate, regulatory notification flag. For MRL-type: pesticide active ingredient, detected residue level, applicable MRL standard (EPA, EU, Codex), exceedance magnitude, affected export market. For food safety incidents: incident subtype (contamination, foreign material, allergen, pathogen, chemical), hazard classification, recall class (I, II, III), mock recall flag, affected quantity and value, regulatory agencies notified, root cause category, and incident closure status. SSOT for ALL quality failures from minor process deviations through food safety crises, recalls, and market withdrawals.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`certificate_of_analysis` (
    `certificate_of_analysis_id` BIGINT COMMENT 'Primary key for certificate_of_analysis',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: FSMA and GFSI require traceable employee sign-off on COA authorization. The existing authorized_by plain-text field is a denormalized employee reference; replacing it with a proper FK enables compli',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: COAs are issued per commodity for export documentation, buyer requirements, and food safety compliance. The existing commodity_type is a denormalized plain attribute. A proper FK to product.commodity ',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: A COA is issued for a specific commodity lot in agriculture (grain, produce). This FK is the foundational food safety traceability link enabling lot-level COA retrieval for buyer acceptance, export ce',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: COA issuance incurs lab testing and certification costs that must be allocated to a cost center. Agriculture operations track quality testing costs by cost center for operational budgeting and varianc',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: COAs in agriculture are issued to specific buyers for commodity lots they are purchasing. The COA issuance to buyer process is fundamental — customers require COAs before accepting delivery. Linking',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: COA issuance per delivery destination: in agriculture, COAs accompany shipments to specific customer receiving locations. Linking COA to delivery_location enables FSMA traceability, cold-chain complia',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Retailer and export market COA requirements mandate field-level origin traceability for fresh produce. certificate_of_analysis has country_of_origin and commodity_type. Linking COA to field enables fa',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: COAs issue a USDA grade determination (usda_grade stored as denormalized text). Linking to grading_standard normalizes the grade reference, enabling buyer contract compliance verification, USDA AMS gr',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to quality.laboratory. Business justification: COAs are issued by specific laboratories. The COA table has issuing_lab_name and lab_accreditation_number (strings) but lacks structured FK. This FK enables joining to get complete laboratory details ',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: COA mrl_compliant flag and pesticide_residue_result_ppm require reference to the specific regulatory tolerance for the active ingredient/commodity/jurisdiction combination. Export market compliance (E',
    `coa_number` STRING COMMENT 'Externally-visible, human-readable identifier for the COA document as issued by the laboratory or quality department. Used on customer-facing documentation and GFSI audit packages.. Valid values are `^COA-[A-Z0-9]{4,20}$`',
    `coa_status` STRING COMMENT 'Current lifecycle status of the COA document. released indicates the COA is approved for customer-facing distribution. superseded indicates a newer version has replaced this record. Drives SAP QM usage decision workflow.. Valid values are `draft|pending_review|approved|released|rejected|superseded`',
    `country_of_origin` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country where the commodity was produced or harvested. Required for COOL (Country of Origin Labeling) compliance under USDA AMS regulations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this COA record was first created in the system. Audit trail field supporting FSMA record-keeping requirements and GFSI documentation retention policies.',
    `expiry_date` DATE COMMENT 'Date after which the COA is no longer considered valid for commercial or regulatory purposes. Typically tied to product shelf life or certification validity period.',
    `gfsi_scheme` STRING COMMENT 'GFSI-recognized food safety certification scheme under which this COA was generated or which governs the testing requirements (SQF, BRC, IFS, FSSC 22000, GLOBALG.A.P.). Determines applicable testing protocols and documentation standards.. Valid values are `SQF|BRC|IFS|FSSC_22000|GLOBALG.A.P.|none`',
    `gmo_status` STRING COMMENT 'GMO testing result for the lot. identity_preserved indicates the lot has been maintained under IP (Identity Preserved) protocols from seed to shipment. Required for EU export documentation and non-GMO customer specifications.. Valid values are `gmo_free|gmo_detected|not_tested|identity_preserved`',
    `haccp_ccp_compliant` BOOLEAN COMMENT 'Indicates whether all HACCP Critical Control Point (CCP) parameters tested in this COA are within established critical limits. False triggers mandatory corrective action under FSMA Preventive Controls and FSIS HACCP regulations.',
    `heavy_metal_type` STRING COMMENT 'Specific heavy metal analyte tested. Each metal has distinct regulatory maximum levels under FDA, Codex Alimentarius, and EU regulations requiring separate tracking.. Valid values are `lead|cadmium|arsenic|mercury|total_heavy_metals`',
    `heavy_metals_result_ppm` DECIMAL(18,2) COMMENT 'Measured concentration of heavy metal contaminants (lead, cadmium, arsenic, mercury) in parts per million. Compared against FDA and Codex Alimentarius maximum levels for food safety compliance.',
    `issue_date` DATE COMMENT 'Date on which the Certificate of Analysis was formally issued and signed off by the authorized laboratory or quality manager. This is the principal business event date for the COA document lifecycle.',
    `microbial_result` DECIMAL(18,2) COMMENT 'Measured microbial count expressed as colony forming units per gram (CFU/g). Covers total plate count, E. coli, Salmonella, Listeria, and other pathogens per HACCP critical control point specifications.',
    `microbial_test_type` STRING COMMENT 'Specific microbiological analyte or pathogen tested. Salmonella and Listeria are HACCP critical control point parameters under FSMA Preventive Controls and FSIS regulations.. Valid values are `total_plate_count|e_coli|salmonella|listeria|coliforms|yeast_mold`',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Measured moisture content of the commodity expressed as a percentage of total weight. Critical quality parameter for grain storage, mold prevention, and commodity grading under USDA AMS standards.',
    `mrl_compliant` BOOLEAN COMMENT 'Indicates whether all pesticide residue results are within the applicable Maximum Residue Limits (MRL) for the target market. True = compliant; False = MRL exceedance detected. Critical for export certification and GLOBALG.A.P. audit readiness.',
    `mycotoxin_result_ppb` DECIMAL(18,2) COMMENT 'Measured concentration of mycotoxins (aflatoxin, deoxynivalenol, fumonisin, ochratoxin, zearalenone) in parts per billion (ppb). Compared against FDA action levels and EU MRL limits for regulatory compliance.',
    `mycotoxin_type` STRING COMMENT 'Specific mycotoxin analyte tested in this COA record. Different mycotoxins have distinct FDA action levels and MRL thresholds under Codex Alimentarius and EU regulations.. Valid values are `aflatoxin|deoxynivalenol|fumonisin|ochratoxin_a|zearalenone|total_mycotoxin`',
    `overall_result` STRING COMMENT 'Aggregate pass/fail determination across all analytical parameters tested. A single fail on any critical parameter (e.g., MRL exceedance, mycotoxin above regulatory limit) results in an overall fail. Drives the release_status decision.. Valid values are `pass|fail|conditional_pass|pending`',
    `pesticide_residue_result_ppm` DECIMAL(18,2) COMMENT 'Measured pesticide residue concentration in parts per million (ppm). Compared against EPA-established Maximum Residue Limits (MRL) and Codex Alimentarius MRL tables for regulatory compliance and export eligibility.',
    `phi_compliant` BOOLEAN COMMENT 'Indicates whether the required Pre-Harvest Interval (PHI) was observed between the last pesticide application and harvest date. True = PHI observed; False = potential PHI violation. Verified against protection_event records.',
    `product_description` STRING COMMENT 'Full descriptive name of the commodity or product as it appears on the COA document, including variety, grade, or specification designation where applicable.',
    `protein_pct` DECIMAL(18,2) COMMENT 'Measured protein content of the commodity expressed as a percentage of dry weight. Key nutritional and commercial quality parameter for grain, feed, and food ingredient specifications.',
    `release_status` STRING COMMENT 'Indicates whether the lot covered by this COA has been approved for customer shipment and commercial release. blocked prevents order fulfillment in SAP SD. Distinct from coa_status which tracks the document lifecycle.. Valid values are `unreleased|released|blocked|conditionally_released`',
    `test_date` DATE COMMENT 'Date on which laboratory analysis was performed on the sample. Used to determine result validity windows and compliance with regulatory testing timelines.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this COA record. Supports audit trail requirements and change management tracking for regulatory documentation integrity.',
    CONSTRAINT pk_certificate_of_analysis PRIMARY KEY(`certificate_of_analysis_id`)
) COMMENT 'Certificate of Analysis (COA) master records for agricultural commodities, processed products, and inputs. Captures issuing laboratory, sample lot reference (LOT), commodity type, test date, analytical parameters tested (moisture, protein, mycotoxin, pesticide residue, heavy metals, microbial counts), pass/fail status per parameter, MRL compliance flags, and customer-facing release status. Integrates with SAP QM usage decision and supports GFSI certification documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`lab_sample` (
    `lab_sample_id` BIGINT COMMENT 'Unique system-generated identifier for each laboratory sample submission record. Primary key for the lab_sample data product in the quality domain.',
    `case_id` BIGINT COMMENT 'Foreign key linking to customer.case. Business justification: Customer complaint sampling: when a customer raises a quality case (e.g., suspected MRL exceedance or contamination), lab samples are collected as investigative evidence. Linking lab_sample to the ori',
    `employee_id` BIGINT COMMENT 'Reference to the employee or field technician who physically collected the sample. Required for chain-of-custody documentation and FSMA traceability.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Agricultural lab sampling plans (FSMA produce safety rule, GAP pesticide residue monitoring) are commodity-specific. A lab manager or food safety coordinator scheduling and tracking samples under comm',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Lab samples in agriculture are drawn from specific commodity lots for pesticide residue, mycotoxin, and moisture testing. lot_number on lab_sample is a denormalization of commodity_lot. This FK is the',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Lab sampling for pesticide residue, mycotoxin, and food safety testing is a direct operational cost. Agriculture quality managers allocate sampling costs to cost centers for budget control and regulat',
    `facility_id` BIGINT COMMENT 'Reference to the facility, farm, processing plant, or warehouse location where the sample was collected. Supports geographic traceability and regulatory site-level reporting.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Field-level lab sampling for pesticide residues, heavy metals, and microbial contamination is a core GAP and FSMA compliance practice. Linking lab_sample to field enables field-level quality history a',
    `field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.equipment_field_operation. Business justification: Lab samples for MRL/residue compliance are collected after specific pesticide application field operations. Linking lab_sample to the originating equipment_field_operation enables PHI/REI compliance v',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: lab_sample has haccp_ccp_flag (BOOLEAN) indicating the sample is associated with a HACCP Critical Control Point. Adding haccp_plan_id FK links the sample to the specific HACCP plan and CCP it monitors',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Lab samples are frequently collected during or as a direct result of quality inspections (field inspections, post-harvest inspections, HACCP monitoring). Linking lab_sample to the triggering inspectio',
    `irrigation_zone_id` BIGINT COMMENT 'Foreign key linking to land.irrigation_zone. Business justification: FSMA Produce Safety Rule §112 mandates irrigation water testing traceable to specific water application zones. Lab samples for ag water quality must reference the irrigation_zone from which water was ',
    `laboratory_id` BIGINT COMMENT 'Reference to the internal or external laboratory assigned to perform testing on this sample. Supports laboratory accreditation tracking and COA generation.',
    `soil_sample_id` BIGINT COMMENT 'Foreign key linking to land.soil_sample. Business justification: When agronomic soil samples are submitted for pesticide residue, heavy metals, or pathogen testing (organic certification, FSMA compliance), the quality lab_sample must reference the originating land.',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Agricultural vendor contracts specify mandatory lab sampling plans (e.g., pesticide residue testing frequency, mycotoxin sampling). Linking lab_sample to vendor_contract enables verification that cont',
    `analytical_method_code` STRING COMMENT 'Code identifying the approved analytical method used for testing this sample (e.g., AOAC 2007.01 for pesticide residues, EPA Method 8270 for organics, USDA FSIS MLG for microbiology). Ensures regulatory acceptance of test results and supports method validation documentation.',
    `chain_of_custody_number` STRING COMMENT 'Unique identifier for the chain-of-custody document accompanying this sample from collection through laboratory receipt. Provides legal defensibility for test results and supports FSMA traceability and regulatory inspection readiness.',
    `coa_number` STRING COMMENT 'Reference number of the Certificate of Analysis (COA) issued by the laboratory upon completion of testing. The COA is the primary quality document used for product release, customer delivery, and regulatory compliance. Aligns with COA business jargon.',
    `collection_point_description` STRING COMMENT 'Specific description of the exact collection point within the facility or field (e.g., North field block 3, row 12, Bin 7 - top layer, Processing Line 2 - post-wash CCP). Provides granular traceability beyond the collection point type classification.',
    `collection_point_type` STRING COMMENT 'Classification of the physical location or process stage where the sample was collected. Supports field-to-COA traceability and HACCP critical control point mapping. Values: field (in-crop collection), bin (grain storage), processing_line (in-process), receiving_dock (incoming goods), storage (warehouse), transport (in-transit).. Valid values are `field|bin|processing_line|receiving_dock|storage|transport`',
    `collection_timestamp` TIMESTAMP COMMENT 'Date and time when the sample was physically collected from the collection point. The principal real-world event time for this transaction. Critical for chain-of-custody integrity, PHI (Pre-Harvest Interval) compliance verification, and FSMA traceability records.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the lab sample record was first created in the data platform. Used for audit trail, data lineage, and Silver layer ingestion tracking.',
    `disposition_action` STRING COMMENT 'Final disposition decision for the physical sample material after testing is complete. Released: sample returned or discarded per protocol after passing; Quarantined: held pending further investigation; Destroyed: sample destroyed per biohazard or regulatory protocol; Returned: sample returned to submitter; Resampled: additional sampling required.. Valid values are `released|quarantined|destroyed|returned|resampled`',
    `disposition_date` DATE COMMENT 'Date on which the final disposition action was executed for the physical sample material. Required for sample retention compliance and laboratory space management.',
    `fsma_sampling_plan_ref` STRING COMMENT 'Reference code or document identifier for the FSMA-compliant sampling plan under which this sample was collected. Supports FDA inspection readiness and FSMA Subpart O environmental monitoring and food safety plan documentation. Aligns with FSMA business jargon.',
    `gfsi_scheme_code` STRING COMMENT 'Identifies the GFSI-benchmarked certification scheme under which this sample was collected or is being used to demonstrate compliance. Supports certification audit readiness for SQF, BRC, IFS, and GLOBALG.A.P. schemes. Aligns with GFSI, SQF, BRC, IFS business jargons.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSSC22000|other`',
    `haccp_ccp_flag` BOOLEAN COMMENT 'Indicates whether this sample was collected as part of HACCP (Hazard Analysis and Critical Control Points) critical control point monitoring or verification activities. True requires enhanced documentation and regulatory retention per FSMA Preventive Controls rule. Aligns with HACCP business jargon.',
    `mrl_exceedance_flag` BOOLEAN COMMENT 'Indicates whether any test parameter in this sample exceeded the applicable Maximum Residue Limit (MRL) as defined by EPA, Codex Alimentarius, or customer specification. True triggers non-conformance workflow and regulatory notification procedures. Aligns with MRL business jargon.',
    `overall_result` STRING COMMENT 'Consolidated pass/fail determination for the sample based on all test parameters in the requested panel against defined acceptance criteria. Pass: all parameters within specification; Fail: one or more parameters exceeded MRL or acceptance threshold; Inconclusive: results require further review; Pending: testing not yet complete.. Valid values are `pass|fail|inconclusive|pending`',
    `phi_compliance_flag` BOOLEAN COMMENT 'Indicates whether the sample collection date was verified to be after the required Pre-Harvest Interval (PHI) for any applied crop protection products. True confirms PHI compliance at time of sampling. Critical for pesticide residue MRL compliance. Aligns with PHI business jargon.',
    `received_at_lab_timestamp` TIMESTAMP COMMENT 'Date and time when the sample was officially received and logged at the testing laboratory. Used to calculate sample transit time, assess sample integrity, and enforce holding time limits per analytical method requirements.',
    `required_completion_date` DATE COMMENT 'Target date by which laboratory testing and result reporting must be completed. Drives laboratory scheduling, SLA monitoring, and release-hold decisions for production lots awaiting quality clearance.',
    `results_released_timestamp` TIMESTAMP COMMENT 'Date and time when the laboratory officially released the test results and COA. Marks the completion of the testing lifecycle and triggers downstream quality disposition workflows in SAP QM.',
    `sample_condition` STRING COMMENT 'Assessment of the physical condition of the sample upon receipt at the laboratory. Acceptable: sample integrity maintained; Compromised: minor integrity issues noted but testing may proceed with caveats; Rejected: sample integrity failed, testing cannot proceed. Drives chain-of-custody decisions.. Valid values are `acceptable|compromised|rejected`',
    `sample_notes` STRING COMMENT 'Free-text field for additional observations, anomalies, or contextual information recorded at the time of sample collection or receipt. Captures field conditions, equipment calibration notes, or deviations from standard sampling protocol that may affect result interpretation.',
    `sample_number` STRING COMMENT 'Externally-known, human-readable unique identifier assigned to the sample at collection or submission. Used for chain-of-custody documentation, COA traceability, and communication with external laboratories. Follows enterprise sample numbering convention (e.g., LAB-2024-000123).. Valid values are `^LAB-[0-9]{4}-[0-9]{6}$`',
    `sample_quantity` DECIMAL(18,2) COMMENT 'Measured quantity of material collected for the sample (e.g., weight in grams, volume in milliliters). Used to verify adequacy of sample size per analytical method requirements and sampling plan specifications.',
    `sample_quantity_uom` STRING COMMENT 'Unit of measure for the sample quantity field. Standard units include grams (g), kilograms (kg), milliliters (mL), liters (L), milligrams (mg), and ounces (oz). Must align with the unit specified in the analytical method.. Valid values are `g|kg|mL|L|mg|oz`',
    `sample_status` STRING COMMENT 'Current lifecycle status of the laboratory sample from submission through disposition. Drives workflow routing in SAP QM and laboratory tracking systems. Values: submitted (collected and logged), received (confirmed at lab), in_testing (analysis underway), completed (results available), rejected (sample failed receipt criteria), disposed (sample destroyed or returned per protocol).. Valid values are `submitted|received|in_testing|completed|rejected|disposed`',
    `sample_type` STRING COMMENT 'Classification of the physical material collected for laboratory analysis. Determines applicable analytical methods, acceptance criteria, and regulatory reporting requirements. [ENUM-REF-CANDIDATE: grain|soil|water|tissue|feed|environmental_swab|air|product — promote to reference product]',
    `sampling_frequency_code` STRING COMMENT 'Classification of why this sample was collected relative to the sampling plan schedule. Routine: scheduled periodic sampling; Triggered: collected in response to an event or non-conformance; Regulatory: mandated by USDA/FDA/EPA inspection; Verification: HACCP verification sampling; Validation: process or method validation sampling.. Valid values are `routine|triggered|regulatory|verification|validation`',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Temperature in degrees Celsius at which the sample was stored during transit and prior to analysis. Critical for maintaining sample integrity for microbiological and chemical analyses. Deviations may invalidate results per ISO/IEC 17025 requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to the lab sample record. Supports incremental data processing in the Databricks Lakehouse Silver layer and audit trail requirements.',
    CONSTRAINT pk_lab_sample PRIMARY KEY(`lab_sample_id`)
) COMMENT 'Laboratory sample submission and tracking records for all quality testing activities. Captures sample collection point (field, bin, processing line, receiving dock), sample type (grain, soil, water, tissue, feed, environmental swab), collection date/time, chain of custody, assigned laboratory, requested test panel, sample condition at receipt, and disposition after testing. Includes testing protocol metadata: sampling plan reference, sampling frequency, approved analytical methods, test parameters, and acceptance criteria. Supports field-to-COA traceability, FSMA sampling plan compliance, and HACCP verification sampling.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`test_result` (
    `test_result_id` BIGINT COMMENT 'Unique system-generated identifier for each individual analytical test result record. Primary key for the test_result data product in the quality domain.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Pesticide residue test results must trace to the specific EPA-registered agrochemical product for MRL compliance reporting, regulatory submission, and resistance management tracking. Agriculture labs ',
    `asset_id` BIGINT COMMENT 'Identifier of the laboratory instrument or equipment used to perform the analysis (e.g., HPLC, GC-MS, PCR thermocycler). Supports instrument calibration traceability and ISO/IEC 17025 audit requirements.',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: test_result has coa_eligible (BOOLEAN) indicating the result qualifies for inclusion in a Certificate of Analysis. Adding coa_id FK links the individual test result to the specific COA it was included',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific commodity lot (batch) from which the sample was drawn. Enables lot-level traceability for COA generation, regulatory reporting, and potential recall management under FSMA.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory analyst who performed the test and is responsible for sign-off on the result. Required for COA generation and regulatory audit trails.',
    `facility_id` BIGINT COMMENT 'Reference to the laboratory (internal or third-party accredited) that performed the analytical test. Supports COA generation and regulatory reporting to USDA, FDA, and FSIS.',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Test results for moisture, protein, test weight, and defects are evaluated against specific grading standards. Linking test_result to grading_standard enables automated pass/fail against official USDA',
    `lab_sample_id` BIGINT COMMENT 'Reference to the parent laboratory sample from which this test result was derived. Links the individual test result to its originating sample submission record.',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: test_result stores mrl_threshold as a denormalized numeric column. Linking to mrl_threshold normalizes the regulatory tolerance reference, enabling pass/fail determination against jurisdiction-specifi',
    `nonconformance_id` BIGINT COMMENT 'Reference to the non-conformance record raised as a result of a failed test result. Populated when pass_fail_status is fail, linking the test result to the corrective action workflow in SAP QM.',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Incoming quality test results (MRL, mycotoxin, germination) must be linked to the specific GRN for lot acceptance/rejection decisions, return claim evidence, and FSMA supplier verification records. te',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: Test results drive stock release decisions in SAP QM — a pass result releases blocked stock, a fail triggers quarantine. Linking test_result to stock_position enables automated QM usage decisions, sto',
    `action_limit` DECIMAL(18,2) COMMENT 'Internal or regulatory action threshold below the MRL that triggers corrective action or investigation before the regulatory limit is breached. Supports HACCP CCP monitoring and FSMA preventive controls.',
    `analyst_signoff_timestamp` TIMESTAMP COMMENT 'The date and time when the laboratory analyst formally reviewed and signed off on the test result. Required for COA issuance and ISO/IEC 17025 quality system compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this test result record was first created in the quality management system. Supports audit trail requirements under FSMA, ISO 22000, and SOX financial reporting controls.',
    `detection_limit` DECIMAL(18,2) COMMENT 'The lowest concentration or quantity of the analyte that can be reliably detected by the test method. Critical for interpreting non-detect results and MRL compliance reporting to FDA and USDA.',
    `dilution_factor` DECIMAL(18,2) COMMENT 'The dilution factor applied to the sample prior to analysis. Used to back-calculate the actual concentration in the original sample matrix and ensure accurate MRL compliance determination.',
    `haccp_ccp_flag` BOOLEAN COMMENT 'Indicates whether this test result is associated with a HACCP Critical Control Point (CCP) monitoring activity. CCP-flagged results require immediate corrective action upon failure and are subject to FSIS and FDA regulatory review.',
    `laboratory_accreditation_number` STRING COMMENT 'The ISO/IEC 17025 or equivalent accreditation number of the laboratory that performed the test. Printed on COAs and required for regulatory submissions to USDA, FDA, and FSIS to validate laboratory competency.',
    `measured_value` DECIMAL(18,2) COMMENT 'The quantitative result of the analytical test as reported by the laboratory instrument or analyst. For qualitative tests (e.g., Salmonella presence/absence), this field is null and qualitative_result is used instead.',
    `parameter_category` STRING COMMENT 'Broad classification of the test parameter type. Supports regulatory reporting segmentation and HACCP critical control point (CCP) categorization. [ENUM-REF-CANDIDATE: mycotoxin|pesticide_residue|microbiological|physical|chemical|nutritional|heavy_metal|sensory — promote to reference product if additional categories are needed]',
    `parameter_name` STRING COMMENT 'Name of the analytical parameter being tested (e.g., aflatoxin B1, glyphosate residue, Salmonella spp., moisture content, pH, Electrical Conductivity (EC), nitrate). Drives COA line-item labeling and MRL threshold comparison.',
    `pass_fail_status` STRING COMMENT 'The compliance determination for this individual test result based on comparison of the measured value against the MRL threshold and action limit. Drives COA issuance, lot release decisions, and regulatory reporting to USDA, FDA, and FSIS.. Valid values are `pass|fail|inconclusive|pending_review`',
    `qualitative_result` STRING COMMENT 'Qualitative outcome for presence/absence or positive/negative tests (e.g., Salmonella not detected, GMO absent). Used when a numeric measured_value is not applicable. Supports FSIS microbiological reporting.. Valid values are `detected|not_detected|present|absent|positive|negative`',
    `quantitation_limit` DECIMAL(18,2) COMMENT 'The lowest concentration at which the analyte can be quantitatively measured with acceptable precision and accuracy. Distinct from LOD; used for MRL compliance determination and COA reporting.',
    `recovery_percent` DECIMAL(18,2) COMMENT 'The percentage recovery of a spiked control sample used to validate the analytical method performance for this test run. Acceptable recovery ranges are defined by AOAC and Codex Alimentarius guidelines (typically 70–120%).',
    `regulatory_program_code` STRING COMMENT 'Code identifying the regulatory monitoring or surveillance program under which this test was conducted (e.g., USDA Pesticide Data Program (PDP), FDA Pesticide Residue Monitoring Program, FSIS National Residue Program (NRP), USDA AMS Microbiological Data Program).',
    `regulatory_submission_required` BOOLEAN COMMENT 'Indicates whether this test result must be reported to a regulatory authority (USDA, FDA, FSIS, EPA, or APHIS). Triggered by failed MRL results, CCP deviations, or mandatory surveillance program requirements.',
    `result_reported_timestamp` TIMESTAMP COMMENT 'The date and time when the test result was formally reported and made available for COA generation and lot release decisions. Used to calculate laboratory turnaround time KPIs.',
    `result_status` STRING COMMENT 'Current workflow status of the test result record within the quality management system. Controls whether the result is eligible for COA inclusion and lot release authorization.. Valid values are `draft|under_review|approved|rejected|cancelled`',
    `result_type` STRING COMMENT 'Indicates whether this result is an original first-run test, a repeat test, a confirmatory test following a suspect result, or a retest after corrective action. Supports regulatory investigation workflows.. Valid values are `original|repeat|confirmatory|retest`',
    `sample_matrix` STRING COMMENT 'The physical material or commodity type being tested (e.g., grain, soil, water, feed, fresh produce, processed food, animal tissue). Determines applicable MRL thresholds and regulatory reporting pathways under USDA, FDA, or FSIS jurisdiction.',
    `test_method_code` STRING COMMENT 'The standardized analytical method reference code used to perform the test (e.g., AOAC 2007.01, ISO 6579, EPA Method 8270D, USDA FSIS MLG 4.10). Required for COA documentation and regulatory method validation compliance.',
    `test_method_name` STRING COMMENT 'Descriptive name of the analytical method used (e.g., AOAC QuEChERS Multi-Residue Pesticide Method, ISO Horizontal Method for Salmonella Detection). Complements the method code for COA readability.',
    `test_notes` STRING COMMENT 'Free-text field for laboratory analyst observations, anomalies, interferences, or qualifications associated with this test result. Supports audit trail documentation and COA footnotes.',
    `test_performed_timestamp` TIMESTAMP COMMENT 'The date and time when the analytical test was physically performed in the laboratory. Distinct from sample receipt and result sign-off timestamps. Critical for FSMA traceability and COA dating.',
    `test_result_number` STRING COMMENT 'Externally-known business identifier for this test result, used on Certificates of Analysis (COA) and regulatory submissions. Typically sourced from SAP QM or the laboratory information management system (LIMS).',
    `uncertainty_value` DECIMAL(18,2) COMMENT 'The expanded measurement uncertainty associated with the test result, expressed in the same unit as the measured value. Required for ISO/IEC 17025 accredited laboratory reporting and MRL compliance boundary decisions.',
    `unit_of_measure` STRING COMMENT 'Unit in which the measured value is expressed (e.g., ppb, ppm, CFU/g, %, mg/kg, pH units, mS/cm for EC). Aligns with Codex Alimentarius and AOAC reporting conventions for regulatory submissions.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this test result record was last modified in the quality management system. Required for data lineage tracking in the Databricks Silver Layer and regulatory audit trail compliance.',
    CONSTRAINT pk_test_result PRIMARY KEY(`test_result_id`)
) COMMENT 'Individual analytical test results associated with a lab sample. Records test parameter name (e.g., aflatoxin, glyphosate residue, Salmonella, moisture content, pH, EC), measured value, unit of measure (ppb, ppm, CFU/g, %), method reference (AOAC, ISO, EPA method), detection limit, MRL threshold, pass/fail determination, and laboratory analyst sign-off. Provides granular traceability for COA generation and regulatory reporting to USDA, FDA, and FSIS.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`haccp_plan` (
    `haccp_plan_id` BIGINT COMMENT 'Unique system-generated identifier for the HACCP plan record. Primary key for this entity. Entity role: MASTER_AGREEMENT — represents a long-running regulatory compliance plan binding a facility/process to documented food safety controls.',
    `commodity_id` BIGINT COMMENT 'Reference to the agricultural commodity or food product category covered by this HACCP plan (e.g., fresh produce, poultry, dairy). Aligns with USDA/FDA commodity classification for regulatory reporting.',
    `facility_id` BIGINT COMMENT 'Reference to the production facility, processing plant, or packing house where this HACCP plan is applied. Links to the facility master record for location, registration, and regulatory context.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: FSMA Produce Safety Rule requires on-farm food safety/HACCP plans scoped to specific farm operations. haccp_plan has fsma_preventive_controls_applicable and plan_scope. Farm unit provides the operatio',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: HACCP plans for chemical CCPs (pesticide residue control points) define critical limits based on MRL thresholds. A food safety manager designing a HACCP plan would reference the applicable MRL thresho',
    `employee_id` BIGINT COMMENT 'Reference to the qualified individual designated as the HACCP team leader responsible for plan development, maintenance, and regulatory compliance. Corresponds to Codex Alimentarius Step 1 (assemble HACCP team).',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: HACCP plans in grain storage and cold chain agriculture govern specific storage locations (CCPs for temperature, fumigation, moisture). haccp_plan has facility_id but not storage_location granularity.',
    `approval_date` DATE COMMENT 'Date on which the current version of the HACCP plan was formally approved by authorized management. Distinct from effective_date; approval may precede implementation.',
    `biological_hazards_identified` BOOLEAN COMMENT 'Indicates whether biological hazards (e.g., Salmonella, E. coli O157:H7, Listeria monocytogenes) were identified as significant hazards requiring a Critical Control Point (CCP) in this HACCP plan.',
    `ccp_count` STRING COMMENT 'Total number of Critical Control Points (CCPs) identified and documented within this HACCP plan. Used for plan completeness validation and audit readiness checks.',
    `ccp_description` STRING COMMENT 'Narrative description of the CCP process step where control is applied (e.g., Pasteurization heat treatment, Metal detection at packaging line exit, Chlorine wash for fresh produce).',
    `ccp_number` STRING COMMENT 'Unique identifier for a specific Critical Control Point within the HACCP plan (e.g., CCP-1B for biological, CCP-2C for chemical, CCP-3P for physical). Used to cross-reference monitoring logs and corrective action records.. Valid values are `^CCP-[0-9]{1,3}[BCPbcp]?$`',
    `chemical_hazards_identified` BOOLEAN COMMENT 'Indicates whether chemical hazards (e.g., pesticide residues exceeding MRL, allergens, mycotoxins, heavy metals, cleaning chemical residues) were identified as significant hazards in this HACCP plan.',
    `corrective_action_procedure` STRING COMMENT 'Documented procedure to be followed when a deviation from the critical limit is detected at the CCP, including product disposition, process correction, and root cause investigation steps. Corresponds to Codex Alimentarius Principle 5.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this HACCP plan record was first created in the system. Supports audit trail, data lineage, and regulatory record-keeping requirements.',
    `critical_limit_description` STRING COMMENT 'Documented critical limit(s) for each CCP that distinguish safe from unsafe product (e.g., Internal temperature ≥ 72°C for ≥ 15 seconds, Chlorine concentration 50–200 ppm, Metal detector sensitivity: 1.5mm ferrous). Corresponds to Codex Alimentarius Principle 3.',
    `deviation_flag` BOOLEAN COMMENT 'Indicates whether any active deviation from a critical limit has been recorded against this HACCP plan in the current monitoring period. True signals that a corrective action is open or pending closure.',
    `effective_date` DATE COMMENT 'Date on which this version of the HACCP plan became operationally effective and was implemented in production. Marks the start of the plans binding period for compliance purposes.',
    `expiry_date` DATE COMMENT 'Date on which this HACCP plan version expires or is scheduled for mandatory reassessment review. Nullable for open-ended plans; populated when a defined review cycle is mandated by the regulatory framework or certification body.',
    `fsma_preventive_controls_applicable` BOOLEAN COMMENT 'Indicates whether this HACCP plan is subject to the FDA Food Safety Modernization Act (FSMA) Preventive Controls for Human Food rule (21 CFR Part 117). False may apply to exempt facilities or animal food operations governed by a separate rule.',
    `gfsi_scheme` STRING COMMENT 'GFSI-benchmarked certification scheme under which this HACCP plan is audited (Safe Quality Food (SQF), British Retail Consortium (BRC), International Featured Standards (IFS), FSSC 22000, or GLOBALG.A.P.). Drives audit scope and documentation requirements.. Valid values are `SQF|BRC|IFS|FSSC_22000|GLOBALG.A.P.|none`',
    `hazard_analysis_summary` STRING COMMENT 'Narrative summary of the hazard analysis conducted for this plan, documenting the methodology used to identify and evaluate biological, chemical, and physical hazards at each process step. Corresponds to Codex Alimentarius Principle 1.',
    `intended_use` STRING COMMENT 'Documented intended use and consumer population for the product covered by this plan, including whether the product is intended for vulnerable populations (e.g., infants, immunocompromised). Informs hazard severity assessment.',
    `last_review_date` DATE COMMENT 'Date of the most recent formal reassessment or revalidation of the HACCP plan, triggered by process changes, new hazard information, regulatory updates, or scheduled periodic review. Required by FDA FSMA and GFSI schemes.',
    `monitoring_frequency` STRING COMMENT 'Frequency at which the monitoring parameter is measured at the CCP (e.g., continuous, every batch, hourly, per shift). Defined in the HACCP plan and enforced during production operations. [ENUM-REF-CANDIDATE: continuous|every_batch|hourly|every_2_hours|daily|per_shift|other — 7 candidates stripped; promote to reference product]',
    `monitoring_method` STRING COMMENT 'Description of the procedure, instrument, or technique used to monitor the CCP parameter (e.g., Calibrated digital thermometer, Inline pH meter, Metal detector test piece challenge). Supports equipment calibration traceability.',
    `monitoring_parameter` STRING COMMENT 'The physical or chemical parameter measured at the CCP to verify the critical limit is being met (e.g., temperature in °C, pH, chlorine concentration in ppm, metal detector sensitivity in mm). Corresponds to Codex Alimentarius Principle 4. [ENUM-REF-CANDIDATE: temperature|pH|chlorine_concentration|metal_detector_sensitivity|water_activity|time|pressure|flow_rate|turbidity|conductivity|other — promote to reference product]',
    `next_review_date` DATE COMMENT 'Date by which the next formal reassessment of the HACCP plan must be completed. Used for compliance calendar management and audit readiness tracking.',
    `open_corrective_actions` STRING COMMENT 'Count of corrective action records currently open and unresolved against this HACCP plan. Used for compliance dashboard monitoring and audit readiness assessment. Zero indicates full compliance.',
    `physical_hazards_identified` BOOLEAN COMMENT 'Indicates whether physical hazards (e.g., metal fragments, glass, bone, hard plastic, stones) were identified as significant hazards requiring a CCP such as metal detection or X-ray inspection in this HACCP plan.',
    `plan_name` STRING COMMENT 'Descriptive human-readable name of the HACCP plan, typically referencing the commodity, process line, or facility scope (e.g., Fresh-Cut Leafy Greens Processing — Facility A).',
    `plan_number` STRING COMMENT 'Externally-known unique alphanumeric identifier for the HACCP plan, used in regulatory submissions, audit documentation, and cross-system references (e.g., SAP QM inspection lot linkage). Format: HACCP-{FACILITY_CODE}-{YEAR}-{SEQ}.. Valid values are `^HACCP-[A-Z0-9]{3,10}-[0-9]{4}-[0-9]{3}$`',
    `plan_scope` STRING COMMENT 'Defines the operational scope of the HACCP plan — whether it covers an entire facility, a specific process line, a commodity category, or a specific finished product. Determines applicability during audits.. Valid values are `facility_wide|process_line|commodity_specific|product_specific|seasonal`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the HACCP plan. active indicates the plan is in operational use; under_review indicates a scheduled reassessment is in progress; suspended indicates temporary halt pending corrective action; superseded indicates replaced by a newer version.. Valid values are `draft|active|under_review|suspended|superseded|archived`',
    `plan_version` STRING COMMENT 'Version number of the HACCP plan document, incremented upon each formal review or revision cycle. Supports document control and audit trail requirements (e.g., 1.0, 2.3).. Valid values are `^[0-9]+.[0-9]+$`',
    `prerequisite_programs` STRING COMMENT 'List of prerequisite programs (PRPs) supporting this HACCP plan, such as Good Manufacturing Practices (GMP), sanitation standard operating procedures (SSOPs), pest control, and allergen management programs. PRPs are foundational controls that underpin the HACCP system.',
    `process_description` STRING COMMENT 'Narrative description of the production or processing scope covered by this HACCP plan, including process flow steps from raw material receipt through finished product dispatch. Required by Codex Alimentarius Step 4 (process flow diagram description).',
    `recordkeeping_requirements` STRING COMMENT 'Description of the records that must be maintained to document HACCP plan implementation, including monitoring logs, corrective action records, verification records, and retention periods. Corresponds to Codex Alimentarius Principle 7.',
    `regulatory_framework` STRING COMMENT 'Primary regulatory or certification framework under which this HACCP plan was developed and is maintained (e.g., FDA FSMA Preventive Controls, FSIS HACCP, GFSI scheme such as SQF or BRC). Determines audit requirements and record retention obligations. [ENUM-REF-CANDIDATE: FDA_FSMA|FSIS_HACCP|USDA_NOP|GLOBALG.A.P.|SQF|BRC|IFS|ISO_22000|Codex_Alimentarius|EU_852_2004|other — promote to reference product]. Valid values are `FDA_FSMA|FSIS_HACCP|USDA_NOP|GLOBALG.A.P.|SQF|BRC|IFS|ISO_22000|Codex_Alimentarius|other`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this HACCP plan record in the system. Used for change tracking, version control, and data synchronization with SAP QM module.',
    `verification_procedure` STRING COMMENT 'Documented activities used to confirm the HACCP plan is functioning effectively, including calibration schedules, record review, periodic product testing, and internal audits. Corresponds to Codex Alimentarius Principle 6.',
    CONSTRAINT pk_haccp_plan PRIMARY KEY(`haccp_plan_id`)
) COMMENT 'HACCP (Hazard Analysis and Critical Control Points) plan master records with embedded CCP monitoring logs for each production process, commodity, or facility. Plan-level: defines process scope, hazard analysis summary, identified biological/chemical/physical hazards, critical control points (CCPs), critical limits, monitoring procedures, corrective action procedures, verification activities, and record-keeping requirements. CCP monitoring log detail: captures real-time or periodic measurements at each CCP including monitoring parameter (temperature, pH, chlorine concentration, metal detector sensitivity), measured value, critical limit, monitoring frequency, operator identity, timestamp, deviation flag, and immediate corrective action taken. Provides both the plan framework and continuous compliance evidence required by FDA FSMA Preventive Controls rule and GFSI scheme auditors (SQF, BRC, IFS).';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`quality_certification` (
    `quality_certification_id` BIGINT COMMENT 'Unique surrogate identifier for each quality and food safety certification record held by the enterprise. Primary key for the quality_certification data product.',
    `certification_record_id` BIGINT COMMENT 'Foreign key linking to customer.certification_record. Business justification: Supplier certification satisfying customer requirement: food manufacturer customers require specific certifications (SQF, GlobalG.A.P.). Linking the producers quality_certification to the customers ',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Quality certifications (GAP, GFSI, GlobalG.A.P.) are scoped to specific commodities — a GlobalG.A.P. certificate for tomatoes is distinct from one for peppers. Certification bodies issue certificates ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Annual certification fees (organic, GFSI, GlobalG.A.P.) are charged to cost centers. Certification cost tracking for management accounting and budget planning in agriculture requires this link to allo',
    `facility_id` BIGINT COMMENT 'Reference to the internal facility or site master record covered by this certification. Links the certificate to the enterprises facility hierarchy for operational and regulatory reporting.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Organic certificates, GlobalG.A.P. certificates, and GAP certifications in agriculture are issued to farm operations. Linking quality_certification to farm_unit enables direct lookup of which certific',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Certification fees and renewal costs are posted to GL accounts as licensing/certification expense. Financial reporting and cost-of-quality analysis require certification costs mapped to a GL account f',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: GFSI certifications (SQF, BRC, IFS) and FSMA compliance certifications are directly tied to the HACCP plans that govern food safety at a facility. A quality certification should reference the HACCP pl',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Facility-level quality certifications for organic operations (USDA NOP) must reference the product-level organic certificate. This link enables NOP compliance verification, certificate renewal coordin',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to land.parcel. Business justification: USDA NOP organic certifications are issued against specific parcels (parcel has organic_certification_status, organic_transition_start_date). quality_certification has usda_organic_op_number. Certifyi',
    `product_certification_id` BIGINT COMMENT 'Foreign key linking to product.product_certification. Business justification: Quality certification audits validate that product-level certifications (Non-GMO Project, Kosher, Halal, SQF) are current and compliant. Linking quality_certification to product_certification enables ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Quality certifications (organic, GlobalG.A.P., GFSI) are tied to profit centers for revenue premium attribution and certification cost P&L reporting. Agriculture operations track certified vs. convent',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: GlobalG.A.P., USDA Organic, and FSMA certifications require a named responsible manager as an accountable employee of record. The existing responsible_manager text field is denormalized; a proper FK',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Organic and food safety certifications (USDA Organic, SQF, BRC) apply to specific storage locations (certified organic bins, temperature-controlled stores). quality_certification has facility_id but n',
    `accreditation_body` STRING COMMENT 'The national or international accreditation body that accredits the certification body (e.g., ANAB - ANSI National Accreditation Board, UKAS - United Kingdom Accreditation Service, DAkkS). Validates the legitimacy of the certification body and is required for GFSI scheme recognition.',
    `audit_type` STRING COMMENT 'The type of audit that resulted in or is associated with this certification record: initial (first-time certification), recertification (renewal at end of cycle), surveillance (periodic interim audit), unannounced (surprise audit required by some GFSI schemes), or extension (scope extension audit).. Valid values are `initial|recertification|surveillance|unannounced|extension`',
    `body` STRING COMMENT 'The name of the accredited third-party certification body or registrar that issued the certificate (e.g., NSF International, SGS, Bureau Veritas, DNV, Intertek). Required for regulatory reporting to USDA, FDA, and FSIS and for GFSI scheme compliance.',
    `certificate_document_ref` STRING COMMENT 'Reference path or document management system identifier pointing to the scanned or digital copy of the issued certificate (e.g., SharePoint URL, SAP DMS document number). Enables direct access to the certificate document for audits and customer requests.',
    `certificate_number` STRING COMMENT 'The externally-issued, unique certificate number assigned by the certification body. Used for regulatory submissions, audit trails, and customer-facing documentation (e.g., COA, supplier declarations). Aligns with SAP S/4HANA QM module certificate tracking.',
    `certification_status` STRING COMMENT 'Current lifecycle status of the certification. Active: certificate is valid and in good standing. Suspended: temporarily halted by the certification body pending corrective action. Withdrawn: permanently revoked. Expired: past the expiry date without renewal. Pending: initial application or renewal in progress. Under_review: surveillance audit or non-conformance review in progress. Drives certification readiness dashboards and renewal workflows.. Valid values are `active|suspended|withdrawn|expired|pending|under_review`',
    `certification_type` STRING COMMENT 'High-level classification of the certification by its primary purpose: food_safety (SQF, BRC, IFS, HACCP-based), environmental (ISO 14001, ISCC), organic (USDA NOP), sustainability (ISCC, Fair Trade), social (Fair Trade), or quality_management (ISO 22000). Supports portfolio-level reporting and gap analysis.. Valid values are `food_safety|environmental|organic|sustainability|social|quality_management`',
    `corrective_action_due_date` DATE COMMENT 'The deadline by which all corrective actions arising from audit non-conformances must be submitted to the certification body. Null if no open non-conformances exist. Drives corrective action workflow and escalation alerts.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where the certified facility or operation is located (e.g., USA, BRA, DEU). Required for COOL (Country of Origin Labeling) compliance and international regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this certification record was first created in the system. Supports audit trail, data lineage, and FSMA record-keeping requirements.',
    `expiry_date` DATE COMMENT 'The date on which the certificate expires and must be renewed to maintain certified status. Null for open-ended certifications. Triggers renewal workflow alerts and drives certification readiness dashboards.',
    `gfsi_scheme_flag` BOOLEAN COMMENT 'Indicates whether this certification is recognized under the Global Food Safety Initiative (GFSI) benchmarking framework (True) or is a non-GFSI scheme (False). GFSI-recognized schemes include SQF, BRC, IFS, FSSC 22000, and GLOBALG.A.P. Critical for customer and retailer compliance requirements.',
    `globalg_ap_producer_number` STRING COMMENT 'The unique GLOBALG.A.P. producer or certificate number assigned by the GLOBALG.A.P. secretariat and published in the GLOBALG.A.P. database. Required for GLOBALG.A.P. certification verification by buyers and retailers.',
    `grade_or_level` STRING COMMENT 'The grade, level, or rating awarded by the certification body upon successful audit (e.g., SQF Level 2, SQF Level 3, BRC Grade AA/A/B/C/D, IFS Higher Level/Foundation Level). Null for schemes that do not use graded outcomes. Used for benchmarking and customer qualification.',
    `initial_certification_date` DATE COMMENT 'The date on which the facility or operation first achieved certification under this scheme, regardless of subsequent renewals. Used to calculate certification tenure and demonstrate long-standing compliance to customers and regulators.',
    `iscc_certificate_number` STRING COMMENT 'The unique certificate number issued under the International Sustainability and Carbon Certification (ISCC) scheme for bioenergy and biomass sustainability compliance. Null for non-ISCC certifications.',
    `issue_date` DATE COMMENT 'The date on which the certification body formally issued the certificate. Marks the start of the certification validity period. Used for compliance tracking and regulatory reporting to USDA, FDA, and FSIS.',
    `multi_site_flag` BOOLEAN COMMENT 'Indicates whether this certificate covers multiple sites or facilities under a single certificate number (True) or a single site (False). Multi-site certifications are common for GLOBALG.A.P. Option 2 and BRC multi-site schemes.',
    `next_audit_date` DATE COMMENT 'The planned date for the next certification or surveillance audit as agreed with the certification body. Drives the surveillance audit schedule and renewal workflow alerts in the certification readiness dashboard.',
    `nonconformance_count_major` STRING COMMENT 'The number of major non-conformances identified during the most recent certification audit. Major non-conformances require corrective action within a defined timeframe and may result in certification suspension if unresolved. Tracked per SAP S/4HANA QM module non-conformance records.',
    `nonconformance_count_minor` STRING COMMENT 'The number of minor non-conformances identified during the most recent certification audit. Minor non-conformances require corrective action but do not immediately threaten certification status. Tracked per SAP S/4HANA QM module.',
    `notes` STRING COMMENT 'Free-text field for additional remarks, conditions, or qualifications associated with the certification (e.g., scope limitations, special conditions imposed by the certification body, internal observations). Supports operational context for quality managers.',
    `product_category_scope` STRING COMMENT 'The product category or commodity type covered by the certification scope as defined by the scheme (e.g., GLOBALG.A.P. crop category: Fruit and Vegetables; BRC product category: Fresh Produce; SQF food sector category). Supports product-level compliance mapping.',
    `renewal_reminder_days` STRING COMMENT 'The number of calendar days before the expiry date at which automated renewal reminder notifications should be triggered. Configurable per scheme to align with certification body lead times and internal preparation requirements.',
    `sap_qm_inspection_lot` STRING COMMENT 'The SAP S/4HANA QM module inspection lot number associated with the certification audit or quality inspection event. Enables traceability between the certification record and the source system inspection record for audit and compliance purposes.',
    `scheme_name` STRING COMMENT 'The name of the food safety or quality certification scheme under which the certificate was issued (e.g., Safe Quality Food (SQF), British Retail Consortium (BRC), International Featured Standards (IFS), GLOBALG.A.P., ISO 22000, USDA Organic/National Organic Program (NOP), International Sustainability and Carbon Certification (ISCC), Fair Trade). Drives certification readiness dashboards and renewal workflows.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|ISO 22000|ISO 14001|USDA Organic|ISCC|Fair Trade|FSMA`',
    `scheme_version` STRING COMMENT 'The edition or version number of the certification scheme standard under which the audit was conducted (e.g., SQF Edition 9, BRC Issue 9, IFS Food Version 8). Critical for tracking standard upgrades and ensuring compliance with the current scheme revision.',
    `scope_description` STRING COMMENT 'Narrative description of the products, processes, activities, or operations covered by the certificate as defined by the certification body (e.g., Production and packing of fresh vegetables, Manufacture of animal feed). Directly reflects the scope statement printed on the certificate.',
    `suspension_date` DATE COMMENT 'The date on which the certification body formally suspended the certificate, if applicable. Null for active or non-suspended certifications. Required for regulatory reporting and customer notification obligations.',
    `suspension_reason` STRING COMMENT 'Narrative description of the reason for certification suspension as communicated by the certification body (e.g., unresolved major non-conformances, product recall, failure to submit corrective actions). Null if not suspended.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this certification record was last modified. Supports audit trail, change tracking, and FSMA record-keeping requirements.',
    `usda_organic_op_number` STRING COMMENT 'The USDA National Organic Program (NOP) operation number assigned to the certified organic operation. Required for USDA organic labeling compliance and traceability under the National Organic Program regulations.',
    `withdrawal_date` DATE COMMENT 'The date on which the certificate was permanently withdrawn or voluntarily surrendered. Null for active certifications. Required for regulatory reporting and audit trail completeness.',
    CONSTRAINT pk_quality_certification PRIMARY KEY(`quality_certification_id`)
) COMMENT 'SSOT for all quality and food safety certifications held by the enterprise, including GFSI scheme certifications (SQF, BRC, IFS), GLOBALG.A.P., USDA Organic (NOP), ISCC, Fair Trade, and ISO 22000/14001. Captures certification body, scheme name, scope of certification, certificate number, issue date, expiry date, surveillance audit schedule, current status (active, suspended, withdrawn), and facility or operation covered. Drives certification readiness dashboards and renewal workflows.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`audit` (
    `audit_id` BIGINT COMMENT 'Unique system-generated identifier for each formal quality or food safety audit record. Primary key for the audit data product.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Quality audits (GAP, GFSI, organic) are scoped to specific commodities. Audit scheduling, scope definition, and certification outcome reporting all require commodity-level audit tracking. A certificat',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Third-party GFSI and GlobalG.A.P. audits incur certification body fees and travel costs charged to cost centers. Certification cost tracking and cost-of-quality management accounting in agriculture re',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Customer-mandated audits (GFSI, GlobalG.A.P., SQF) are a standard agriculture commercial requirement — buyers require certified suppliers. Linking audit to the requesting customer account enables cust',
    `employee_id` BIGINT COMMENT 'Reference to the lead auditor or auditing body representative responsible for conducting this audit.',
    `facility_id` BIGINT COMMENT 'Reference to the facility, farm, processing plant, or operational site that was the subject of this audit.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: USDA Organic, GlobalG.A.P., and GFSI scheme audits are issued to farm operations. Linking audit to farm_unit enables the farm-level audit history required for certification renewal, buyer qualificatio',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP audits and organic certification audits are conducted at the field level. Linking audit to field enables field-level audit history and traceability of which fields are GAP-certified — a named requ',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Audit fees (certification body, third-party auditor) are posted to GL accounts as certification/compliance expense. Financial period-close and cost-of-quality P&L reporting require audit costs mapped ',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Quality audits (GFSI, GLOBALG.A.P., internal HACCP verification audits) are conducted to verify the adequacy and implementation of HACCP plans. A quality audit should reference the specific HACCP plan',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to land.parcel. Business justification: Organic certification audits (USDA NOP) and GlobalG.A.P. audits require parcel-level legal land traceability. Parcel holds organic_certification_status and organic_transition_start_date. Auditors must',
    `previous_audit_quality_audit_id` BIGINT COMMENT 'Reference to the immediately preceding audit record for the same facility and standard, enabling trend analysis and certification history tracking.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Quality audits are conducted for specific business units whose P&L is tracked by profit center. Audit costs and certification outcomes (premium market access, suspension) directly affect profit center',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Vendor qualification audits (second-party audits) are a named procurement process in agriculture — quality_audit records vendor facility assessments for GlobalG.A.P., GFSI, and FSMA compliance. qualit',
    `workforce_certification_id` BIGINT COMMENT 'Foreign key linking to the specific worker certification or license that was reviewed during this audit.',
    `actual_end_date` DATE COMMENT 'The actual calendar date on which the audit concluded, including closing meeting. Used to calculate audit duration and track completion.',
    `actual_start_date` DATE COMMENT 'The actual calendar date on which the audit commenced on-site or remotely. May differ from scheduled_date due to rescheduling.',
    `announced` BOOLEAN COMMENT 'Indicates whether the auditee was given advance notice of the audit (True = announced, False = unannounced). Unannounced audits are required by certain standards (e.g., BRC unannounced option) and carry higher credibility with retail customers.',
    `audit_method` STRING COMMENT 'The method by which the audit was conducted: on_site (physical presence at the facility), remote (conducted via video/document sharing), hybrid (combination of on-site and remote), or document_review (desk-based review only).. Valid values are `on_site|remote|hybrid|document_review`',
    `audit_number` STRING COMMENT 'Externally-known, human-readable unique reference number assigned to this audit, used in correspondence, reports, and regulatory submissions. Follows the format AUD-YYYY-NNNNNN.. Valid values are `^AUD-[0-9]{4}-[0-9]{6}$`',
    `audit_scope` STRING COMMENT 'Narrative description of the operations, processes, product categories, or geographic areas covered by this audit (e.g., Fresh produce packing and cold storage operations, Grain receiving and storage — Facility A).',
    `audit_status` STRING COMMENT 'Current lifecycle state of the audit record, tracking progression from scheduling through completion or cancellation.. Valid values are `scheduled|in_progress|completed|cancelled|on_hold`',
    `audit_type` STRING COMMENT 'Classification of the audit by party relationship: internal (first-party, conducted by own staff), second_party (customer or buyer-initiated), third_party (independent certification body), regulatory (government agency), or surveillance (periodic check between full certification cycles).. Valid values are `internal|second_party|third_party|regulatory|surveillance`',
    `auditing_body` STRING COMMENT 'Name of the certification body, regulatory agency, or organization that conducted or commissioned the audit (e.g., NSF International, SGS, Bureau Veritas, USDA AMS, FDA).',
    `auditor_notes` STRING COMMENT 'Free-text notes recorded by the auditor regarding this specific credential during this specific audit. May include observations about renewal status, scope limitations, or corrective action recommendations specific to this credential review.',
    `certificate_expiry_date` DATE COMMENT 'The date on which the current certificate expires and recertification is required. Critical for audit program scheduling and maintaining uninterrupted certification status.',
    `certificate_issue_date` DATE COMMENT 'The date on which the certification body formally issued the certificate following a successful audit. Marks the start of the certification validity period.',
    `certificate_number` STRING COMMENT 'The unique certificate number issued by the certification body upon successful audit completion. Used for regulatory submissions, customer verification, and GFSI database registration.',
    `certification_outcome` STRING COMMENT 'The formal certification decision resulting from the audit: certified (new certification granted), recertified (existing certification renewed), conditional (certification granted with conditions), suspended (certification temporarily withdrawn), withdrawn (certification permanently revoked), or not_certified (audit failed).. Valid values are `certified|recertified|conditional|suspended|withdrawn|not_certified`',
    `certification_standard` STRING COMMENT 'The formal quality or food safety standard against which this audit was conducted (e.g., SQF, BRC, IFS, GLOBALG.A.P., USDA Organic, ISO 22000, HACCP, GAP). [ENUM-REF-CANDIDATE: SQF|BRC|IFS|GLOBALG.A.P.|USDA_Organic|ISO_22000|HACCP|GAP|GMP|FSMA — promote to reference product]',
    `corrective_action_closed_date` DATE COMMENT 'The date on which all corrective actions from this audit were formally accepted and closed by the auditing body or internal quality team. Null if corrective actions are still open.',
    `corrective_action_due_date` DATE COMMENT 'The deadline by which all required corrective actions from this audit must be submitted to the auditing body or documented as completed. Null if no corrective actions are required.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether one or more corrective actions are required as a result of this audit. True when any major or minor non-conformances were identified that mandate a formal corrective action response.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this audit record was first created in the system. Used for data lineage, audit trail, and Silver layer ingestion tracking.',
    `duration_days` STRING COMMENT 'Total number of calendar days the audit spanned from actual start to actual end. Used for audit program benchmarking and resource planning.',
    `finding_if_expired` STRING COMMENT 'The formal audit finding recorded if the credential was expired, lapsed, or otherwise non-compliant at the time of the audit review. Populated only when the credential failed verification; null if the credential was current and valid.',
    `fsma_rule` STRING COMMENT 'The specific FSMA rule or subpart applicable to this audit, if the audit is FSMA-related (e.g., Produce Safety Rule, Preventive Controls for Human Food, Foreign Supplier Verification Program). Null for non-FSMA audits.',
    `gap_certified` BOOLEAN COMMENT 'Indicates whether this audit resulted in or maintained a Good Agricultural Practices (GAP) certification. Relevant for USDA GAP/GHP audits and GLOBALG.A.P. assessments.',
    `grade` STRING COMMENT 'Letter grade or categorical rating assigned as the audit outcome per the applicable standard (e.g., BRC AA/A/B/C/D, SQF Excellent/Good/Satisfactory/Unsatisfactory). Null if the standard uses numeric score only. [ENUM-REF-CANDIDATE: AA|A|B|C|D|Excellent|Good|Satisfactory|Unsatisfactory — 9 candidates stripped; promote to reference product]',
    `lead_auditor_credential` STRING COMMENT 'Professional certification or credential held by the lead auditor (e.g., SQF Practitioner, PCQI, REHS, ISO 22000 Lead Auditor). Validates auditor competency for the standard being assessed.',
    `lead_auditor_name` STRING COMMENT 'Full name of the lead auditor who conducted the audit. Captured for traceability and credential verification purposes.',
    `major_nonconformance_count` STRING COMMENT 'Total number of major non-conformances (critical findings) identified during the audit. Major non-conformances typically jeopardize certification and require immediate corrective action.',
    `minor_nonconformance_count` STRING COMMENT 'Total number of minor non-conformances identified during the audit. Minor non-conformances require corrective action within a defined timeframe but do not immediately jeopardize certification.',
    `next_audit_due_date` DATE COMMENT 'The date by which the next audit (recertification or surveillance) must be completed to maintain continuous certification status. Derived from certificate expiry and standard-specific surveillance requirements.',
    `notes` STRING COMMENT 'Free-text field for additional context, special conditions, auditor remarks, or internal quality team commentary not captured in structured fields.',
    `observation_count` STRING COMMENT 'Total number of observations or opportunities for improvement noted during the audit. Observations are not non-conformances but indicate areas where practices could be strengthened.',
    `overall_score` DECIMAL(18,2) COMMENT 'Numeric score or percentage achieved in the audit against the applicable standard. Scoring methodology varies by standard (e.g., SQF uses percentage, BRC uses weighted scoring). Null if the standard uses grade-only outcomes.',
    `report_issued_date` DATE COMMENT 'The date on which the formal audit report was issued by the auditing body to the auditee. Marks the start of the corrective action response window.',
    `report_number` STRING COMMENT 'The unique reference number of the formal audit report document issued by the auditing body. Used for document management, regulatory submissions, and customer sharing.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which the audit was originally scheduled to begin. Used for audit program planning and resource coordination.',
    `site_audit_scope` STRING COMMENT 'Narrative description of the operations, processes, or product categories audited at this specific trial site within the broader audit engagement. May differ from the overall audit scope when a multi-site audit covers different activities at each site.',
    `site_certification_outcome` STRING COMMENT 'The formal certification decision for this specific trial site resulting from the audit. In multi-site campaigns, individual sites may receive different outcomes (e.g., one site certified, another conditionally certified). Cannot reside on audit alone as it varies per site.',
    `standard_version` STRING COMMENT 'The specific version or edition of the certification standard used for this audit (e.g., SQF Edition 9, BRC Issue 9, IFS Food Version 8). Critical for tracking compliance against evolving standard requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this audit record was last modified. Used for change tracking, data synchronization with SAP S/4HANA QM module, and Silver layer delta processing.',
    `verification_date` DATE COMMENT 'The specific date on which the auditor verified this credential during the audit. Distinct from workforce_certification.verification_date, which records the general HR verification date independent of any audit.',
    `verified_flag` BOOLEAN COMMENT 'Indicates whether the certification or license was confirmed as current, valid, and compliant at the time of this audit review. True means the auditor verified the credential was in good standing during the audit; false indicates it could not be verified or was found non-compliant.',
    CONSTRAINT pk_audit PRIMARY KEY(`audit_id`)
) COMMENT 'Master record for all formal quality and food safety audits including internal audits, second-party customer audits, and third-party certification audits (SQF, BRC, IFS, GLOBALG.A.P., USDA Organic). Captures audit type, auditing body or auditor name, audit scope, facility or operation audited, scheduled and actual audit dates, audit standard and version, overall grade or score, and certification outcome. Distinct from operational inspections — audits are formal system-level assessments against a defined standard.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`laboratory` (
    `laboratory_id` BIGINT COMMENT 'Primary key for laboratory',
    `parent_laboratory_id` BIGINT COMMENT 'Self-referencing FK on laboratory (parent_laboratory_id)',
    `accreditation_body` STRING COMMENT 'Name of the accreditation body that granted laboratory certification (e.g., A2LA, ANAB, UKAS).',
    `accreditation_effective_date` DATE COMMENT 'Date when the laboratory accreditation became effective.',
    `accreditation_expiration_date` DATE COMMENT 'Date when the current laboratory accreditation expires and requires renewal.',
    `accreditation_number` STRING COMMENT 'Unique accreditation certificate number issued by the accreditation body.',
    `accreditation_status` STRING COMMENT 'Current accreditation status of the laboratory under ISO/IEC 17025 or equivalent standards.',
    `address_line_1` STRING COMMENT 'Primary street address of the laboratory facility.',
    `address_line_2` STRING COMMENT 'Secondary address information such as suite, building, or floor number.',
    `biosafety_level` STRING COMMENT 'Biosafety level classification for laboratories handling biological agents.',
    `city` STRING COMMENT 'City where the laboratory is located.',
    `clia_certificate_number` STRING COMMENT 'CLIA certificate number if laboratory performs clinical testing on agricultural workers or food safety personnel.',
    `country_code` STRING COMMENT 'Three-letter ISO country code where the laboratory is located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this laboratory record was first created in the system.',
    `data_integrity_compliance` BOOLEAN COMMENT 'Indicates whether the laboratory meets data integrity requirements under ALCOA+ principles (Attributable, Legible, Contemporaneous, Original, Accurate, Complete, Consistent, Enduring, Available).',
    `equipment_calibration_frequency_days` STRING COMMENT 'Standard frequency in days for calibration of laboratory testing equipment.',
    `established_date` DATE COMMENT 'Date when the laboratory was established and began operations.',
    `fda_registration_number` STRING COMMENT 'FDA registration number for laboratories conducting food safety testing under FSMA requirements.',
    `gfsi_certification_scheme` STRING COMMENT 'GFSI-recognized certification scheme the laboratory operates under (e.g., SQF, BRC, IFS, FSSC 22000). [ENUM-REF-CANDIDATE: SQF|BRC|IFS|FSSC_22000|GLOBALG.A.P.|PrimusGFS|CanadaGAP — promote to reference product]',
    `laboratory_code` STRING COMMENT 'Externally-known unique code for the laboratory used in regulatory filings and certifications.',
    `laboratory_name` STRING COMMENT 'Official registered name of the laboratory facility.',
    `laboratory_type` STRING COMMENT 'Classification of laboratory based on operational model and ownership structure.',
    `last_audit_date` DATE COMMENT 'Date of the most recent external audit or assessment of the laboratory.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this laboratory record was last updated.',
    `lims_system_name` STRING COMMENT 'Name of the Laboratory Information Management System used for sample tracking and data management.',
    `next_audit_scheduled_date` DATE COMMENT 'Scheduled date for the next external audit or surveillance assessment.',
    `operational_status` STRING COMMENT 'Current operational status of the laboratory facility.',
    `postal_code` STRING COMMENT 'Postal or ZIP code for the laboratory location.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary laboratory contact for quality and compliance communications.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary contact person or laboratory director.',
    `primary_contact_phone` STRING COMMENT 'Primary phone number for the laboratory contact.',
    `proficiency_testing_participation` BOOLEAN COMMENT 'Indicates whether the laboratory participates in proficiency testing programs to validate testing competency.',
    `quality_management_system` STRING COMMENT 'Quality management system framework the laboratory operates under.',
    `specialization_area` STRING COMMENT 'Primary area of laboratory specialization (e.g., microbiology, chemistry, pesticide residue, mycotoxin, allergen, GMO, nutritional analysis).',
    `state_province` STRING COMMENT 'State or province where the laboratory is located.',
    `testing_capacity_samples_per_day` STRING COMMENT 'Maximum number of samples the laboratory can process per day under normal operating conditions.',
    `testing_scope` STRING COMMENT 'Comprehensive description of testing capabilities and scope of accreditation including test methods and matrices.',
    `turnaround_time_standard_hours` STRING COMMENT 'Standard turnaround time in hours for routine test results from sample receipt to report delivery.',
    `usda_establishment_number` STRING COMMENT 'USDA establishment number for laboratories testing meat, poultry, and egg products.',
    CONSTRAINT pk_laboratory PRIMARY KEY(`laboratory_id`)
) COMMENT 'Master reference table for laboratory. Referenced by laboratory_id.';

